                                                {(c.classificacio || []).map(u => (
                                                    <div key={u.user_id} className="flex items-center gap-3 px-2 py-1 rounded-lg bg-gray-900/50">
                                                        <span className={`text-xs font-bold w-6 text-center flex-shrink-0 ${
                                                            u.posicio === 1 ? 'text-yellow-400' :
