import { createClient } from '@supabase/supabase-js'

const supabaseAdmin = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL,
    process.env.SUPABASE_SERVICE_KEY
)

const BIWENGER_URL  = 'https://cf.biwenger.com/api/v2/competitions/la-liga/data?lang=ca&score=2'
const FOTO_BASE     = 'https://biwenger.as.com/res/images/players/icon_'   // + id + .png
const ESCUDO_BASE   = 'https://biwenger.as.com/res/images/clubs/badge_'    // + teamId + .png

const POS_MAP = { 1: 'Porter', 2: 'Defensa', 3: 'Migcampista', 4: 'Davanter' }

function calcValor(price) {
    if (!price) return 6
    if (price >= 70_000_000) return 10
    if (price >= 40_000_000) return 9
    if (price >= 20_000_000) return 8
    if (price >= 10_000_000) return 7
    return 6
}

async function doSync() {
    const res = await fetch(BIWENGER_URL, {
        headers: { 'User-Agent': 'Mozilla/5.0' },
        cache: 'no-store'
    })
    if (!res.ok) throw new Error(`Biwenger API error: ${res.status}`)
    const json = await res.json()

    const teamsRaw   = json.data?.teams   || {}
    const playersRaw = json.data?.players || {}

    // Mapa equips id → nom
    const teamNames = {}
    Object.values(teamsRaw).forEach(t => { teamNames[t.id] = t.name })

    // Mapeig jugadors — camps correctes: team (no teamID), price (no fantasyPrice)
    const jugadors = Object.values(playersRaw)
        .filter(p => POS_MAP[p.position])
        .map(p => {
            // El camp equip pot venir com a p.team o p.teamID
            const teamId = p.team ?? p.teamID ?? null
            return {
                id:            p.id,
                nombre:        p.name,
                posicion:      POS_MAP[p.position],
                equipo_real:   teamNames[teamId] || 'Desconegut',
                valor:         calcValor(p.price ?? p.fantasyPrice),
                precio:        p.price ?? p.fantasyPrice ?? 0,
                punts_totals:  p.points ?? 0,
                status:        typeof p.status === 'string' ? p.status : 'ok',
                // Foto garantida: URL pública sense dependre del camp iconHero
                foto:          `${FOTO_BASE}${p.id}.png`,
                escudo_equip:  teamId ? `${ESCUDO_BASE}${teamId}.png` : null,
            }
        })

    // Upsert — usa 'id' com a clau de conflicte
    const { error } = await supabaseAdmin
        .from('players')
        .upsert(jugadors, { onConflict: 'id' })

    if (error) throw new Error(error.message)
    return jugadors.length
}

export async function POST(request) {
    const { secret } = await request.json().catch(() => ({}))
    if (process.env.SYNC_SECRET && secret !== process.env.SYNC_SECRET) {
        return Response.json({ error: 'No autoritzat' }, { status: 401 })
    }
    try {
        const total = await doSync()
        return Response.json({ ok: true, total, message: `${total} jugadors sincronitzats correctament` })
    } catch (err) {
        return Response.json({ error: err.message }, { status: 500 })
    }
}

// Vercel Cron crida GET
export async function GET(request) {
    const authHeader = request.headers.get('authorization')
    if (authHeader !== `Bearer ${process.env.CRON_SECRET}`) {
        return Response.json({ error: 'No autoritzat' }, { status: 401 })
    }
    try {
        const total = await doSync()
        return Response.json({ ok: true, total, message: `Cron: ${total} jugadors sincronitzats` })
    } catch (err) {
        return Response.json({ error: err.message }, { status: 500 })
    }
}

'use client'
import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '../../lib/supabase'
import Navbar from '../components/Navbar'

const POS_COLORS = {
    Porter:      { bg: 'bg-yellow-500', text: 'text-yellow-900' },
    Defensa:     { bg: 'bg-blue-500',   text: 'text-blue-900'   },
    Migcampista: { bg: 'bg-green-500',  text: 'text-green-900'  },
    Davanter:    { bg: 'bg-red-500',    text: 'text-red-900'    },
}

export default function CanviBomba() {
    const [user, setUser]                   = useState(null)
    const [perfil, setPerfil]               = useState(null)
    const [loading, setLoading]             = useState(true)
    const [jornada, setJornada]             = useState(0)       // jornada actual detectada
    const [meusPicks, setMeusPicks]         = useState([])      // jugadors del meu equip (objectes)
    const [jugadorsDisponibles, setJugadorsDisponibles] = useState([]) // no triats per ningú
    const [usadaV1, setUsadaV1]             = useState(false)
    const [usadaV2, setUsadaV2]             = useState(false)
    const [historial, setHistorial]         = useState([])      // tots els canvis bomba de tots
    const [profiles, setProfiles]           = useState([])

    // Formulari actiu
    const [voltaActiva, setVoltaActiva]     = useState(null)    // 1 | 2 | null
    const [jugadorSurt, setJugadorSurt]     = useState(null)
    const [jugadorEntra, setJugadorEntra]   = useState(null)
    const [cercaDisp, setCercaDisp]         = useState('')
    const [posFiltre, setPosFiltre]         = useState('Tots')
    const [confirmant, setConfirmant]       = useState(false)
    const [missatge, setMissatge]           = useState('')

    const router = useRouter()

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) { router.push('/login'); return }
            setUser(data.user)
            fetchTot(data.user.id)
        })
    }, [])

    async function fetchTot(userId) {
        const [
            { data: perfilData },
            { data: puntsData },
            { data: picks },
            { data: allPlayers },
            { data: bombesData },
            { data: profilesData },
        ] = await Promise.all([
            supabase.from('profiles').select('id, nom, email').eq('id', userId).single(),
            supabase.from('player_punts').select('jornada').order('jornada', { ascending: false }).limit(1),
            supabase.from('draft_picks').select('player_id, user_id'),
            supabase.from('players').select('*').order('posicion').order('nombre'),
            supabase.from('canvi_bomba').select('*').order('created_at', { ascending: false }),
            supabase.from('profiles').select('id, nom, email'),
        ])

        setPerfil(perfilData)
        setProfiles(profilesData || [])

        // Jornada actual = màxima jornada amb punts registrats
        const jornadaActual = puntsData?.[0]?.jornada || 0
        setJornada(jornadaActual)

        // Jugadors de l'usuari
        const myPickIds = new Set((picks || []).filter(p => p.user_id === userId).map(p => p.player_id))
        const allPickIds = new Set((picks || []).map(p => p.player_id))
        const meus = (allPlayers || []).filter(p => myPickIds.has(p.id))
        const disp = (allPlayers || []).filter(p => !allPickIds.has(p.id))
        setMeusPicks(meus)
        setJugadorsDisponibles(disp)

        // Bombes usades per l'usuari
        const mesBombes = (bombesData || []).filter(b => b.user_id === userId)
        setUsadaV1(mesBombes.some(b => b.volta === 1))
        setUsadaV2(mesBombes.some(b => b.volta === 2))

        // Historial complet amb noms de jugadors i usuaris
        const allPlayersMap = {}
        ;(allPlayers || []).forEach(p => { allPlayersMap[p.id] = p })
        const hist = (bombesData || []).map(b => ({
            ...b,
            jugadorSurtObj:  allPlayersMap[b.jugador_surt],
            jugadorEntraObj: allPlayersMap[b.jugador_entra],
        }))
        setHistorial(hist)

        setLoading(false)
    }

    async function confirmarCanviBomba() {
        if (!jugadorSurt || !jugadorEntra || !voltaActiva) return
        setConfirmant(true)
        setMissatge('')

        // 1. Inserir a canvi_bomba
        const { error: errBomba } = await supabase.from('canvi_bomba').insert({
            user_id:       user.id,
            volta:         voltaActiva,
            jugador_surt:  jugadorSurt.id,
            jugador_entra: jugadorEntra.id,
        })
        if (errBomba) {
            setMissatge('❌ Error: ' + errBomba.message)
            setConfirmant(false)
            return
        }

        // 2. Actualitzar draft_picks: eliminar el que surt, afegir el nou
        await supabase.from('draft_picks').delete().eq('user_id', user.id).eq('player_id', jugadorSurt.id)
        await supabase.from('draft_picks').insert({ player_id: jugadorEntra.id, user_id: user.id, torn: -1 })

        // 3. Actualitzar teams.alineacio si el jugador sortint era titular
        const { data: teamData } = await supabase.from('teams').select('id, alineacio').eq('user_id', user.id).single()
        if (teamData?.alineacio) {
            const alineacio = { ...teamData.alineacio }
            let canviat = false
            Object.entries(alineacio).forEach(([key, val]) => {
                if (val === jugadorSurt.id) { alineacio[key] = jugadorEntra.id; canviat = true }
            })
            if (canviat) await supabase.from('teams').update({ alineacio }).eq('id', teamData.id)
        }

        setMissatge(`✅ Canvi BOMBA ${voltaActiva}a volta fet! ${jugadorSurt.nombre} → ${jugadorEntra.nombre}`)
        setVoltaActiva(null)
        setJugadorSurt(null)
        setJugadorEntra(null)
        setCercaDisp('')
        setConfirmant(false)
        await fetchTot(user.id)
        setTimeout(() => setMissatge(''), 5000)
    }

    // ── Helpers UI ───────────────────────────────────────────────────
    const disponiblesFiltrats = jugadorsDisponibles.filter(p => {
        const okCerca = cercaDisp === '' || p.nombre.toLowerCase().includes(cercaDisp.toLowerCase()) || (p.equipo_real || '').toLowerCase().includes(cercaDisp.toLowerCase())
        const okPos = posFiltre === 'Tots' || p.posicion === posFiltre
        return okCerca && okPos
    })

    function badgePos(pos) {
        const c = POS_COLORS[pos] || { bg: 'bg-gray-600', text: 'text-white' }
        return <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full ${c.bg} ${c.text}`}>{pos?.slice(0,3).toUpperCase()}</span>
    }

    function formatPreu(precio) {
        if (!precio) return '—'
        if (precio >= 1_000_000) return (precio / 1_000_000).toFixed(1) + 'M'
        if (precio >= 1_000) return Math.round(precio / 1_000) + 'K'
        return precio.toString()
    }

    if (loading) return (
        <>
            <Navbar />
            <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">Carregant...</div>
        </>
    )

    const pot1aVolta = !usadaV1 && jornada >= 1 && jornada <= 19
    const pot2aVolta = !usadaV2 && jornada >= 20 && jornada <= 38

    return (
        <>
            <Navbar />
            <main className="min-h-screen bg-gray-950 text-white p-4 md:p-6">
                <div className="max-w-4xl mx-auto">

                    {/* Capçalera */}
                    <div className="mb-6">
                        <h1 className="text-3xl font-bold text-red-400 mb-1"> Canvi BOMBA</h1>
                        <p className="text-gray-400 text-sm">
                            Canvia un jugador de la teva plantilla per un de disponible · Una sola vegada per volta
                        </p>
                        <p className="text-gray-600 text-xs mt-1">
                            Jornada actual detectada: <span className="text-white font-semibold">{jornada === 0 ? 'Sense dades' : `J${jornada}`}</span>
                        </p>
                    </div>

                    {missatge && (
                        <div className={`border px-4 py-3 rounded-xl mb-5 text-sm font-medium ${missatge.includes('❌') ? 'bg-red-900 border-red-500 text-red-300' : 'bg-green-900 border-green-500 text-green-300'}`}>
                            {missatge}
                        </div>
                    )}

                    {/* ── Botons de volta ── */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                        {/* 1a Volta */}
                        <div className={`rounded-2xl border p-5 ${usadaV1 ? 'bg-gray-900 border-gray-700 opacity-60' : jornada > 19 ? 'bg-gray-900 border-gray-700 opacity-50' : 'bg-red-950/40 border-red-700'}`}>
                            <div className="flex items-center gap-3 mb-3">
                                <span className="text-3xl"></span>
                                <div>
                                    <p className="text-white font-bold text-lg">1a Volta</p>
                                    <p className="text-gray-400 text-xs">Jornades 1 – 19</p>
                                </div>
                                {usadaV1 && <span className="ml-auto text-xs bg-gray-700 text-gray-400 px-2 py-1 rounded-full">✓ Usada</span>}
                                {!usadaV1 && jornada > 19 && <span className="ml-auto text-xs bg-gray-700 text-gray-500 px-2 py-1 rounded-full">Expirada</span>}
                                {!usadaV1 && jornada >= 1 && jornada <= 19 && <span className="ml-auto text-xs bg-green-700 text-green-200 px-2 py-1 rounded-full">Disponible</span>}
                                {!usadaV1 && jornada === 0 && <span className="ml-auto text-xs bg-yellow-700/50 text-yellow-400 px-2 py-1 rounded-full">Pendent</span>}
                            </div>
                            <button
                                onClick={() => { setVoltaActiva(voltaActiva === 1 ? null : 1); setJugadorSurt(null); setJugadorEntra(null); setCercaDisp('') }}
                                disabled={!pot1aVolta}
                                className={`w-full py-3 rounded-xl font-bold text-sm transition
                                    ${!pot1aVolta
                                        ? 'bg-gray-800 text-gray-600 cursor-not-allowed'
                                        : voltaActiva === 1
                                            ? 'bg-red-400 text-white'
                                            : 'bg-red-600 hover:bg-red-500 text-white'
                                    }`}>
                                {usadaV1 ? '✓ Canvi BOMBA 1a Volta ja usat' : voltaActiva === 1 ? '✕ Cancel·lar' : ' ACTIVAR CANVI BOMBA 1a Volta'}
                            </button>
                        </div>

                        {/* 2a Volta */}
                        <div className={`rounded-2xl border p-5 ${usadaV2 ? 'bg-gray-900 border-gray-700 opacity-60' : jornada < 20 ? 'bg-gray-900 border-gray-700 opacity-50' : 'bg-orange-950/40 border-orange-700'}`}>
                            <div className="flex items-center gap-3 mb-3">
                                <span className="text-3xl"></span>
                                <div>
                                    <p className="text-white font-bold text-lg">2a Volta</p>
                                    <p className="text-gray-400 text-xs">Jornades 20 – 38</p>
                                </div>
                                {usadaV2 && <span className="ml-auto text-xs bg-gray-700 text-gray-400 px-2 py-1 rounded-full">✓ Usada</span>}
                                {!usadaV2 && jornada < 20 && <span className="ml-auto text-xs bg-gray-700 text-gray-500 px-2 py-1 rounded-full">No disponible</span>}
                                {!usadaV2 && jornada >= 20 && <span className="ml-auto text-xs bg-green-700 text-green-200 px-2 py-1 rounded-full">Disponible</span>}
                            </div>
                            <button
                                onClick={() => { setVoltaActiva(voltaActiva === 2 ? null : 2); setJugadorSurt(null); setJugadorEntra(null); setCercaDisp('') }}
                                disabled={!pot2aVolta}
                                className={`w-full py-3 rounded-xl font-bold text-sm transition
                                    ${!pot2aVolta
                                        ? 'bg-gray-800 text-gray-600 cursor-not-allowed'
                                        : voltaActiva === 2
                                            ? 'bg-orange-400 text-white'
                                            : 'bg-orange-600 hover:bg-orange-500 text-white'
                                    }`}>
                                {usadaV2 ? '✓ Canvi BOMBA 2a Volta ja usat' : voltaActiva === 2 ? '✕ Cancel·lar' : ' ACTIVAR CANVI BOMBA 2a Volta'}
                            </button>
                        </div>
                    </div>

                    {/* ── Formulari de canvi ── */}
                    {voltaActiva && (
                        <div className="bg-gray-900 border border-red-700/50 rounded-2xl p-5 mb-8 animate-in">
                            <h2 className="text-white font-bold text-lg mb-4">
                                 Selecciona el canvi — {voltaActiva === 1 ? '1a' : '2a'} Volta
                            </h2>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                                {/* ── Esquerra: Jugador que SURT ── */}
                                <div>
                                    <p className="text-red-400 font-semibold text-sm mb-2"> Jugador que SURT del teu equip</p>
                                    <div className="space-y-1 max-h-72 overflow-y-auto pr-1">
                                        {['Porter', 'Defensa', 'Migcampista', 'Davanter'].map(pos => {
                                            const del = meusPicks.filter(j => j.posicion === pos)
                                            if (!del.length) return null
                                            return (
                                                <div key={pos}>
                                                    <p className="text-gray-600 text-[10px] uppercase tracking-wider mt-2 mb-1">{pos}s</p>
                                                    {del.map(j => (
                                                        <button
                                                            key={j.id}
                                                            onClick={() => setJugadorSurt(jugadorSurt?.id === j.id ? null : j)}
                                                            className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg mb-1 transition text-left border
                                                                ${jugadorSurt?.id === j.id
                                                                    ? 'bg-red-900/60 border-red-500'
                                                                    : 'bg-gray-800 hover:bg-red-950/40 border-transparent hover:border-red-700'
                                                                }`}>
                                                            <div className="relative w-8 h-8 flex-shrink-0">
                                                                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${POS_COLORS[j.posicion]?.bg} ${POS_COLORS[j.posicion]?.text}`}>
                                                                    {j.nombre?.charAt(0)}
                                                                </div>
                                                                {j.foto && <img src={j.foto} alt="" className="w-8 h-8 rounded-full object-cover absolute inset-0" onError={e => { e.target.style.display='none' }} />}
                                                            </div>
                                                            <div className="flex-1 min-w-0">
                                                                <p className="text-white text-xs font-medium truncate">{j.nombre}</p>
                                                                <div className="flex items-center gap-1">
                                                                    {j.escudo_equip && <img src={j.escudo_equip} alt="" className="w-3 h-3 object-contain" onError={e => { e.target.style.display='none' }} />}
                                                                    <p className="text-gray-500 text-[10px] truncate">{j.equipo_real}</p>
                                                                </div>
                                                            </div>
                                                            {badgePos(j.posicion)}
                                                            {jugadorSurt?.id === j.id && <span className="text-red-400 text-xs">✓</span>}
                                                        </button>
                                                    ))}
                                                </div>
                                            )
                                        })}
                                    </div>
                                </div>

                                {/* ── Dreta: Jugador que ENTRA ── */}
                                <div>
                                    <p className="text-green-400 font-semibold text-sm mb-2"> Jugador que ENTRA a la teva plantilla</p>
                                    <input
                                        type="text"
                                        placeholder=" Cercar jugador disponible..."
                                        value={cercaDisp}
                                        onChange={e => setCercaDisp(e.target.value)}
                                        className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-xs placeholder-gray-500 focus:outline-none focus:border-green-500 mb-2"
                                    />
                                    <div className="flex gap-1 mb-2 flex-wrap">
                                        {['Tots', 'Porter', 'Defensa', 'Migcampista', 'Davanter'].map(pos => (
                                            <button key={pos} onClick={() => setPosFiltre(pos)}
                                                    className={`px-2 py-1 rounded text-[10px] font-bold transition
                                                        ${posFiltre === pos ? 'bg-green-500 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                                                {pos === 'Tots' ? 'Tots' : pos.slice(0,3).toUpperCase()}
                                            </button>
                                        ))}
                                    </div>
                                    <div className="space-y-1 max-h-64 overflow-y-auto pr-1">
                                        {disponiblesFiltrats.length === 0 ? (
                                            <p className="text-gray-600 text-xs text-center py-4">Sense jugadors disponibles</p>
                                        ) : (
                                            disponiblesFiltrats.map(j => (
                                                <button
                                                    key={j.id}
                                                    onClick={() => setJugadorEntra(jugadorEntra?.id === j.id ? null : j)}
                                                    className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg mb-0.5 transition text-left border
                                                        ${jugadorEntra?.id === j.id
                                                            ? 'bg-green-900/60 border-green-500'
                                                            : 'bg-gray-800 hover:bg-green-950/40 border-transparent hover:border-green-700'
                                                        }`}>
                                                    <div className="relative w-8 h-8 flex-shrink-0">
                                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${POS_COLORS[j.posicion]?.bg} ${POS_COLORS[j.posicion]?.text}`}>
                                                            {j.nombre?.charAt(0)}
                                                        </div>
                                                        {j.foto && <img src={j.foto} alt="" className="w-8 h-8 rounded-full object-cover absolute inset-0" onError={e => { e.target.style.display='none' }} />}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <p className="text-white text-xs font-medium truncate">{j.nombre}</p>
                                                        <div className="flex items-center gap-1">
                                                            {j.escudo_equip && <img src={j.escudo_equip} alt="" className="w-3 h-3 object-contain" onError={e => { e.target.style.display='none' }} />}
                                                            <p className="text-gray-500 text-[10px] truncate">{j.equipo_real}</p>
                                                        </div>
                                                    </div>
                                                    <div className="text-right flex-shrink-0">
                                                        {badgePos(j.posicion)}
                                                        <p className="text-green-400 text-[10px] font-bold mt-0.5">{formatPreu(j.precio)}</p>
                                                    </div>
                                                    {jugadorEntra?.id === j.id && <span className="text-green-400 text-xs">✓</span>}
                                                </button>
                                            ))
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* Resum + Confirmar */}
                            {jugadorSurt && jugadorEntra && (
                                <div className="mt-5 bg-gray-800 border border-gray-600 rounded-xl p-4">
                                    <p className="text-gray-400 text-xs uppercase tracking-wider mb-3">Resum del canvi BOMBA</p>
                                    <div className="flex items-center gap-3 flex-wrap">
                                        <div className="flex items-center gap-2 bg-red-950/40 border border-red-800 rounded-lg px-3 py-2">
                                            <span className="text-red-400 text-sm"></span>
                                            <span className="text-white text-sm font-semibold">{jugadorSurt.nombre}</span>
                                            <span className="text-gray-500 text-xs">{jugadorSurt.equipo_real}</span>
                                        </div>
                                        <span className="text-gray-400 text-xl">→</span>
                                        <div className="flex items-center gap-2 bg-green-950/40 border border-green-800 rounded-lg px-3 py-2">
                                            <span className="text-green-400 text-sm"></span>
                                            <span className="text-white text-sm font-semibold">{jugadorEntra.nombre}</span>
                                            <span className="text-gray-500 text-xs">{jugadorEntra.equipo_real}</span>
                                        </div>
                                    </div>
                                    <button
                                        onClick={confirmarCanviBomba}
                                        disabled={confirmant}
                                        className="mt-4 w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-3 rounded-xl font-bold text-sm transition">
                                        {confirmant ? '⏳ Confirmant...' : ` CONFIRMAR CANVI BOMBA ${voltaActiva === 1 ? '1a' : '2a'} VOLTA`}
                                    </button>
                                    <p className="text-gray-600 text-xs text-center mt-2">⚠️ Aquesta acció no es pot desfer i consumirà el Canvi BOMBA de la {voltaActiva === 1 ? '1a' : '2a'} volta</p>
                                </div>
                            )}
                        </div>
                    )}

                    {/* ── Historial de tots els canvis BOMBA ── */}
                    <div className="bg-gray-900 border border-gray-700 rounded-2xl p-5">
                        <h2 className="text-white font-bold text-lg mb-4"> Historial de Canvis BOMBA</h2>
                        {historial.length === 0 ? (
                            <p className="text-gray-600 text-sm text-center py-6">Encara no hi ha canvis BOMBA registrats.</p>
                        ) : (
                            <div className="space-y-2">
                                {historial.map(b => {
                                    const propietari = profiles.find(p => p.id === b.user_id)
                                    const surt  = b.jugadorSurtObj
                                    const entra = b.jugadorEntraObj
                                    const data  = new Date(b.created_at).toLocaleDateString('ca-ES', { day: '2-digit', month: 'short', year: 'numeric' })
                                    return (
                                        <div key={b.id} className="flex items-center gap-3 bg-gray-800 rounded-xl px-4 py-3 flex-wrap">
                                            <span className={`text-xs font-bold px-2 py-0.5 rounded-full flex-shrink-0 ${b.volta === 1 ? 'bg-red-700 text-red-200' : 'bg-orange-700 text-orange-200'}`}>
                                                 {b.volta === 1 ? '1a' : '2a'} Volta
                                            </span>
                                            <span className="text-gray-300 text-sm font-semibold flex-shrink-0">
                                                {propietari?.nom || propietari?.email?.split('@')[0] || '?'}
                                            </span>
                                            <div className="flex items-center gap-2 flex-1 flex-wrap">
                                                <div className="flex items-center gap-1.5 bg-red-950/50 rounded-lg px-2 py-1">
                                                    {surt?.foto && <img src={surt.foto} alt="" className="w-5 h-5 rounded-full object-cover" onError={e => { e.target.style.display='none' }} />}
                                                    <span className="text-red-300 text-xs font-medium">{surt?.nombre || `ID:${b.jugador_surt}`}</span>
                                                    {surt && badgePos(surt.posicion)}
                                                </div>
                                                <span className="text-gray-500 text-sm">→</span>
                                                <div className="flex items-center gap-1.5 bg-green-950/50 rounded-lg px-2 py-1">
                                                    {entra?.foto && <img src={entra.foto} alt="" className="w-5 h-5 rounded-full object-cover" onError={e => { e.target.style.display='none' }} />}
                                                    <span className="text-green-300 text-xs font-medium">{entra?.nombre || `ID:${b.jugador_entra}`}</span>
                                                    {entra && badgePos(entra.posicion)}
                                                </div>
                                            </div>
                                            <span className="text-gray-600 text-xs flex-shrink-0">{data}</span>
                                        </div>
                                    )
                                })}
                            </div>
                        )}
                    </div>

                </div>
            </main>
        </>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { supabase } from '../../lib/supabase'
import Navbar from '../components/Navbar'

const POS_COLORS = {
    Porter:      { bg: 'bg-yellow-400', text: 'text-yellow-900' },
    Defensa:     { bg: 'bg-blue-500',   text: 'text-blue-900'   },
    Migcampista: { bg: 'bg-green-400',  text: 'text-green-900'  },
    Davanter:    { bg: 'bg-red-500',    text: 'text-red-900'    },
}

const posicions = ['Porter', 'Defensa', 'Migcampista', 'Davanter']

function HistorialCanvis({ canvisPicks, players, participants }) {
    if (!canvisPicks.length) return null
    return (
        <div className="bg-gray-900 border border-gray-800 rounded-xl p-4 mt-5">
            <p className="text-gray-400 text-xs uppercase tracking-wider font-semibold mb-3">Canvis realitzats</p>
            <div className="space-y-2">
                {canvisPicks.map(c => {
                    const out  = players.find(p => p.id === c.player_out)
                    const inn  = players.find(p => p.id === c.player_in)
                    const part = participants.find(p => p.id === c.user_id)
                    return (
                        <div key={c.id} className="flex items-center gap-2 bg-gray-800 rounded-lg p-2.5 text-sm flex-wrap">
                            <span className="text-gray-300 font-semibold w-28 truncate flex-shrink-0">{part?.nom || '?'}</span>
                            <span className="text-red-400 flex-1 truncate min-w-0">↑ {out?.nombre || '?'}</span>
                            <span className="text-gray-600">→</span>
                            <span className="text-green-400 flex-1 truncate min-w-0">↓ {inn?.nombre || '?'}</span>
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

export default function Canvis() {
    const [user, setUser]                 = useState(null)
    const [loading, setLoading]           = useState(true)
    const [canvisData, setCanvisData]     = useState(null)
    const [participants, setParticipants] = useState([])
    const [meusPicks, setMeusPicks]       = useState([])
    const [totsElsPicks, setTotsElsPicks] = useState([])
    const [players, setPlayers]           = useState([])
    const [canvisPicks, setCanvisPicks]   = useState([])

    const [playerOut, setPlayerOut]       = useState(null)
    const [playerIn, setPlayerIn]         = useState(null)
    const [confirmant, setConfirmant]     = useState(false)
    const [showConfirm, setShowConfirm]   = useState(false)
    const [cerca, setCerca]               = useState('')
    const [posicioFiltro, setPosicioFiltro] = useState('Tots')

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) return
            setUser(data.user)
            fetchTot(data.user.id)
        })
        const canal = supabase.channel('canvis-canal')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'canvis' }, () => fetchCanvis())
            .on('postgres_changes', { event: '*', schema: 'public', table: 'canvis_picks' }, () => {
                fetchCanvisPicks()
                supabase.auth.getUser().then(({ data }) => data.user && fetchMeusPicks(data.user.id))
            })
            .subscribe()
        return () => supabase.removeChannel(canal)
    }, [])

    async function fetchTot(userId) {
        await Promise.all([
            fetchCanvis(), fetchParticipants(), fetchPlayers(),
            fetchMeusPicks(userId), fetchTotsElsPicks(), fetchCanvisPicks()
        ])
        setLoading(false)
    }

    async function fetchCanvis() {
        const { data } = await supabase.from('canvis').select('*')
            .order('created_at', { ascending: false }).limit(1).single()
        setCanvisData(data)
    }
    async function fetchParticipants() {
        const { data } = await supabase.from('profiles').select('id, nom, email')
        setParticipants(data || [])
    }
    async function fetchPlayers() {
        const { data } = await supabase.from('players').select('*').order('posicion').order('nombre')
        setPlayers(data || [])
    }
    async function fetchMeusPicks(userId) {
        const { data } = await supabase.from('draft_picks').select('player_id').eq('user_id', userId)
        setMeusPicks(data?.map(p => p.player_id) || [])
    }
    async function fetchTotsElsPicks() {
        const { data } = await supabase.from('draft_picks').select('player_id, user_id')
        setTotsElsPicks(data || [])
    }
    async function fetchCanvisPicks() {
        const { data } = await supabase.from('canvis_picks').select('*').order('torn')
        setCanvisPicks(data || [])
    }

    async function ferCanvi() {
        if (!playerOut || !playerIn || !canvisData || !user) return
        setConfirmant(true)
        try {
            await supabase.from('canvis_picks').insert({
                canvi_id: canvisData.id, user_id: user.id,
                player_out: playerOut.id, player_in: playerIn.id,
                torn: canvisData.torn_actual
            })
            await supabase.from('draft_picks').delete().eq('user_id', user.id).eq('player_id', playerOut.id)
            await supabase.from('draft_picks').insert({ user_id: user.id, player_id: playerIn.id, torn: -1 })

            const { data: team } = await supabase.from('teams').select('alineacio').eq('user_id', user.id).single()
            if (team?.alineacio) {
                const nova = { ...team.alineacio }
                const keyOut = Object.entries(nova).find(([, v]) => v === playerOut.id)?.[0]
                if (keyOut) {
                    if (playerIn.posicion === playerOut.posicion) nova[keyOut] = playerIn.id
                    else delete nova[keyOut]
                    await supabase.from('teams').update({ alineacio: nova }).eq('user_id', user.id)
                }
            }

            const ordre = canvisData.ordre_participants || []
            const nouTorn = canvisData.torn_actual + 1
            await supabase.from('canvis').update({
                torn_actual: nouTorn,
                estat: nouTorn >= ordre.length ? 'finalitzat' : 'actiu'
            }).eq('id', canvisData.id)

            setPlayerOut(null); setPlayerIn(null); setShowConfirm(false)
            await fetchTot(user.id)
        } catch (e) { console.error(e) }
        setConfirmant(false)
    }

    const ordre      = canvisData?.ordre_participants || []
    const userActual = ordre[canvisData?.torn_actual ?? 0]
    const esMeuTorn  = userActual === user?.id
    const nomActual  = participants.find(p => p.id === userActual)?.nom || '...'
    const jaHeCanviat = canvisPicks.some(c => c.user_id === user?.id)

    const pickIds      = new Set(totsElsPicks.map(p => p.player_id))
    const meusPickIds  = new Set(meusPicks)
    const meusJugadors = players.filter(p => meusPickIds.has(p.id))
    const disponibles  = players.filter(p => {
        if (pickIds.has(p.id)) return false
        const okC = cerca === '' || p.nombre.toLowerCase().includes(cerca.toLowerCase()) ||
            (p.equipo_real || '').toLowerCase().includes(cerca.toLowerCase())
        return okC && (posicioFiltro === 'Tots' || p.posicion === posicioFiltro)
    })

    if (loading) return (<><Navbar /><div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">Carregant...</div></>)

    return (
        <>
            <Navbar />
            <main className="min-h-screen bg-gray-950 text-white p-4 md:p-6">
                <div className="max-w-6xl mx-auto">
                    <div className="mb-5">
                        <h1 className="text-2xl font-bold text-blue-400"> Ronda de Canvis</h1>
                        <p className="text-gray-400 text-sm">Canvia un jugador del teu equip per un de disponible al mercat</p>
                    </div>

                    {/* PENDENT */}
                    {(!canvisData || canvisData.estat === 'pendent') && (
                        <div className="max-w-md mx-auto text-center bg-gray-900 border border-gray-700 rounded-xl p-10">
                            <div className="text-5xl mb-4">⏳</div>
                            <h2 className="text-white font-bold text-xl mb-2">Ronda de canvis no iniciada</h2>
                            <p className="text-gray-400 text-sm">L&apos;administrador iniciarà la ronda. L&apos;ordre serà l&apos;invers de la classificació general.</p>
                        </div>
                    )}

                    {/* ACTIU */}
                    {canvisData?.estat === 'actiu' && (
                        <>
                            {/* Banner */}
                            <div className={`rounded-xl p-3 mb-5 text-center border ${esMeuTorn && !jaHeCanviat ? 'bg-blue-900/50 border-blue-500 animate-pulse' : 'bg-gray-900 border-gray-700'}`}>
                                <p className="text-xs text-gray-400 mb-0.5">Torn {(canvisData.torn_actual || 0) + 1} de {ordre.length}</p>
                                {esMeuTorn && !jaHeCanviat
                                    ? <p className="text-blue-300 font-bold text-lg"> És el teu torn! Selecciona el teu canvi</p>
                                    : jaHeCanviat
                                        ? <p className="text-green-400 font-semibold">✅ Ja has realitzat el teu canvi aquesta ronda</p>
                                        : <p className="text-white font-semibold">⏳ Esperant que <span className="text-yellow-400">{nomActual}</span> faci el seu canvi...</p>
                                }
                            </div>

                            {/* Progrés */}
                            <div className="bg-gray-900 border border-gray-800 rounded-xl p-3 mb-5">
                                <p className="text-gray-500 text-xs uppercase tracking-wider mb-2 font-semibold">Ordre (invers classificació general)</p>
                                <div className="flex flex-wrap gap-2">
                                    {ordre.map((uid, idx) => {
                                        const part = participants.find(p => p.id === uid)
                                        const fet = canvisPicks.some(c => c.user_id === uid)
                                        const cur = idx === (canvisData.torn_actual || 0)
                                        return (
                                            <span key={uid} className={`text-xs px-3 py-1.5 rounded-full font-medium border
                                                ${fet ? 'bg-green-900/40 border-green-700 text-green-300' :
                                                  cur ? 'bg-blue-600 border-blue-400 text-white' :
                                                        'bg-gray-800 border-gray-700 text-gray-400'}`}>
                                                {fet ? '✓ ' : cur ? '→ ' : ''}
                                                {part?.nom || uid.slice(0, 8)}{uid === user?.id ? ' (tu)' : ''}
                                            </span>
                                        )
                                    })}
                                </div>
                            </div>

                            {/* Selecció (només si és el meu torn) */}
                            {esMeuTorn && !jaHeCanviat && (
                                <>
                                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-5 mb-5">
                                        {/* MEU EQUIP */}
                                        <div className="bg-gray-900 border border-gray-800 rounded-xl p-4">
                                            <p className="text-white font-semibold mb-3 flex items-center gap-2 flex-wrap">
                                                <span className="bg-red-600 text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center flex-shrink-0">1</span>
                                                Qui <span className="text-red-400 font-bold">surt</span> del teu equip?
                                                {playerOut && <span className="text-red-400 text-xs ml-auto">↑ {playerOut.nombre}</span>}
                                            </p>
                                            <div className="space-y-1 max-h-80 overflow-y-auto pr-1">
                                                {posicions.map(pos => {
                                                    const del = meusJugadors.filter(j => j.posicion === pos)
                                                    if (!del.length) return null
                                                    const colors = POS_COLORS[pos]
                                                    return (
                                                        <div key={pos}>
                                                            <p className="text-gray-600 text-[10px] uppercase tracking-wider mt-2 mb-1">{pos}s</p>
                                                            {del.map(j => (
                                                                <button key={j.id} onClick={() => setPlayerOut(playerOut?.id === j.id ? null : j)}
                                                                        className={`w-full flex items-center gap-2 p-2.5 rounded-lg border transition mb-1 text-left
                                                                            ${playerOut?.id === j.id ? 'bg-red-900/50 border-red-500 ring-1 ring-red-400' : 'bg-gray-800 border-gray-700 hover:bg-red-900/20 hover:border-red-900'}`}>
                                                                    {j.foto
                                                                        ? <img src={j.foto} alt={j.nombre} className="w-8 h-8 rounded-full object-cover flex-shrink-0 bg-gray-700" onError={e => { e.target.style.display = 'none' }} />
                                                                        : <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center text-xs font-bold ${colors.bg} ${colors.text}`}>{j.nombre?.charAt(0)}</div>
                                                                    }
                                                                    <span className="text-white text-sm flex-1 truncate font-medium">{j.nombre}</span>
                                                                    <span className="text-gray-500 text-xs hidden md:block truncate max-w-20">{j.equipo_real}</span>
                                                                    <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full flex-shrink-0 ${colors.bg} ${colors.text}`}>{pos.slice(0,3).toUpperCase()}</span>
                                                                </button>
                                                            ))}
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        </div>

                                        {/* DISPONIBLES */}
                                        <div className="bg-gray-900 border border-gray-800 rounded-xl p-4">
                                            <p className="text-white font-semibold mb-3 flex items-center gap-2 flex-wrap">
                                                <span className="bg-green-600 text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center flex-shrink-0">2</span>
                                                Qui <span className="text-green-400 font-bold">entra</span> al teu equip?
                                                {playerIn && <span className="text-green-400 text-xs ml-auto">↓ {playerIn.nombre}</span>}
                                            </p>
                                            <div className="flex gap-1.5 mb-3 flex-wrap">
                                                <input type="text" placeholder=" Cercar..." value={cerca} onChange={e => setCerca(e.target.value)}
                                                       className="flex-1 min-w-28 bg-gray-800 border border-gray-700 rounded-lg px-3 py-1.5 text-white text-xs placeholder-gray-500 focus:outline-none focus:border-blue-500" />
                                                {['Tots', ...posicions].map(pos => (
                                                    <button key={pos} onClick={() => setPosicioFiltro(pos)}
                                                            className={`px-2.5 py-1.5 rounded-lg text-[10px] font-bold transition ${posicioFiltro === pos ? 'bg-blue-600 text-white' : 'bg-gray-700 text-gray-400 hover:bg-gray-600'}`}>
                                                        {pos === 'Tots' ? 'Tots' : pos.slice(0, 3).toUpperCase()}
                                                    </button>
                                                ))}
                                            </div>
                                            <div className="space-y-1 max-h-72 overflow-y-auto pr-1">
                                                {disponibles.length === 0
                                                    ? <p className="text-gray-500 text-sm text-center py-8">Cap jugador disponible{cerca ? ` per &ldquo;${cerca}&rdquo;` : ''}</p>
                                                    : disponibles.map(j => {
                                                        const colors = POS_COLORS[j.posicion]
                                                        return (
                                                            <button key={j.id} onClick={() => setPlayerIn(playerIn?.id === j.id ? null : j)}
                                                                    className={`w-full flex items-center gap-2 p-2.5 rounded-lg border transition mb-1 text-left
                                                                        ${playerIn?.id === j.id ? 'bg-green-900/50 border-green-500 ring-1 ring-green-400' : 'bg-gray-800 border-gray-700 hover:bg-green-900/20 hover:border-green-900'}`}>
                                                                {j.foto
                                                                    ? <img src={j.foto} alt={j.nombre} className="w-8 h-8 rounded-full object-cover flex-shrink-0 bg-gray-700" onError={e => { e.target.style.display = 'none' }} />
                                                                    : <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center text-xs font-bold ${colors.bg} ${colors.text}`}>{j.nombre?.charAt(0)}</div>
                                                                }
                                                                <span className="text-white text-sm flex-1 truncate font-medium">{j.nombre}</span>
                                                                <span className="text-green-400 text-xs flex-shrink-0">{j.precio ? (j.precio/1_000_000).toFixed(1)+'M' : ''}</span>
                                                                <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full flex-shrink-0 ${colors.bg} ${colors.text}`}>{j.posicion?.slice(0,3).toUpperCase()}</span>
                                                            </button>
                                                        )
                                                    })
                                                }
                                            </div>
                                        </div>
                                    </div>

                                    <button onClick={() => playerOut && playerIn && setShowConfirm(true)}
                                            disabled={!playerOut || !playerIn}
                                            className="w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed text-white font-bold py-3.5 rounded-xl transition text-sm">
                                        {playerOut && playerIn
                                            ? ` Confirmar canvi: ${playerOut.nombre} → ${playerIn.nombre}`
                                            : 'Selecciona primer el jugador que surt i el que entra'}
                                    </button>
                                </>
                            )}

                            <HistorialCanvis canvisPicks={canvisPicks} players={players} participants={participants} />
                        </>
                    )}

                    {/* FINALITZAT */}
                    {canvisData?.estat === 'finalitzat' && (
                        <>
                            <div className="bg-green-900/30 border border-green-700 rounded-xl p-5 mb-5 text-center">
                                <div className="text-3xl mb-2">✅</div>
                                <p className="text-green-300 font-bold text-lg">Ronda de canvis completada</p>
                                <p className="text-gray-400 text-sm mt-1">Tots els participants han realitzat el seu canvi</p>
                            </div>
                            <HistorialCanvis canvisPicks={canvisPicks} players={players} participants={participants} />
                        </>
                    )}
                </div>
            </main>

            {/* Modal confirmació */}
            {showConfirm && playerOut && playerIn && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
                    <div className="bg-gray-900 border border-gray-700 rounded-2xl p-6 max-w-sm w-full shadow-2xl">
                        <div className="text-center mb-4">
                            <div className="text-3xl mb-1"></div>
                            <h3 className="text-white font-bold text-lg">Confirmar canvi</h3>
                        </div>
                        <div className="space-y-2.5 mb-5">
                            <div className="flex items-center gap-3 bg-red-950/60 border border-red-800 rounded-xl p-3">
                                {playerOut.foto && <img src={playerOut.foto} alt="" className="w-9 h-9 rounded-full object-cover bg-gray-700" onError={e => { e.target.style.display = 'none' }} />}
                                <div>
                                    <p className="text-red-400 text-[10px] font-bold uppercase">Surt ↑</p>
                                    <p className="text-white font-semibold text-sm">{playerOut.nombre}</p>
                                    <p className="text-gray-400 text-xs">{playerOut.equipo_real} · {playerOut.posicion}</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3 bg-green-950/60 border border-green-800 rounded-xl p-3">
                                {playerIn.foto && <img src={playerIn.foto} alt="" className="w-9 h-9 rounded-full object-cover bg-gray-700" onError={e => { e.target.style.display = 'none' }} />}
                                <div>
                                    <p className="text-green-400 text-[10px] font-bold uppercase">Entra ↓</p>
                                    <p className="text-white font-semibold text-sm">{playerIn.nombre}</p>
                                    <p className="text-gray-400 text-xs">{playerIn.equipo_real} · {playerIn.posicion} · {playerIn.precio ? (playerIn.precio/1_000_000).toFixed(1)+'M' : ''}</p>
                                </div>
                            </div>
                        </div>
                        <div className="flex gap-3">
                            <button onClick={() => setShowConfirm(false)} disabled={confirmant}
                                    className="flex-1 bg-gray-800 hover:bg-gray-700 text-white py-2.5 rounded-xl font-medium transition disabled:opacity-50">
                                Cancel·lar
                            </button>
                            <button onClick={ferCanvi} disabled={confirmant}
                                    className="flex-1 bg-blue-600 hover:bg-blue-500 text-white py-2.5 rounded-xl font-bold transition disabled:opacity-50">
                                {confirmant ? 'Processant...' : 'Confirmar'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { supabase } from '../../lib/supabase'
import Link from 'next/link'

export default function Classificacio() {
    const [ranking, setRanking] = useState([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        fetchRanking()
    }, [])

    async function fetchRanking() {
        const { data: picks } = await supabase.from('draft_picks').select('user_id')
        const { data: perfils } = await supabase.from('profiles').select('id, nom, email')

        if (!picks) { setLoading(false); return }

        const comptador = {}
        picks.forEach(pick => {
            comptador[pick.user_id] = (comptador[pick.user_id] || 0) + 1
        })

        const llista = Object.entries(comptador).map(([userId, total]) => {
            const perfil = perfils?.find(p => p.id === userId)
            return {
                userId,
                total,
                nom: perfil?.nom || perfil?.email || userId.slice(0, 8) + '...'
            }
        }).sort((a, b) => b.total - a.total)

        setRanking(llista)
        setLoading(false)
    }

    if (loading) return (
        <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">
            Carregant...
        </div>
    )

    return (
        <main className="min-h-screen bg-gray-950 text-white p-8">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-green-400"> Classificació</h1>
                    <p className="text-gray-400">Jugadors triats per participant</p>
                </div>
                <Link href="/draft" className="bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg text-sm transition">
                    Anar al Draft
                </Link>
            </div>

            {ranking.length === 0 ? (
                <p className="text-gray-500 text-center mt-20">Encara no hi ha picks al draft</p>
            ) : (
                <div className="max-w-2xl mx-auto">
                    {ranking.map((participant, index) => (
                        <div key={participant.userId} className="flex items-center gap-4 bg-gray-900 border border-gray-800 rounded-xl p-4 mb-3">
                            <div className="text-2xl font-bold w-10 text-center">
                                {index === 0 ? '' : index === 1 ? '' : index === 2 ? '' : index + 1}
                            </div>
                            <div className="flex-1">
                                <div className="font-semibold">{participant.nom}</div>
                                <div className="text-gray-400 text-sm">{participant.total} jugadors triats</div>
                            </div>
                            <div className="text-green-400 font-bold text-xl">0 pts</div>
                        </div>
                    ))}
                </div>
            )}
        </main>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { supabase } from '../../lib/supabase'
import Link from 'next/link'
import Navbar from '../components/Navbar'

const FORMACIONS = {
    '4-4-2':  { Porter: 1, Defensa: 4, Migcampista: 4, Davanter: 2 },
    '4-3-3':  { Porter: 1, Defensa: 4, Migcampista: 3, Davanter: 3 },
    '4-5-1':  { Porter: 1, Defensa: 4, Migcampista: 5, Davanter: 1 },
    '3-4-3':  { Porter: 1, Defensa: 3, Migcampista: 4, Davanter: 3 },
    '3-5-2':  { Porter: 1, Defensa: 3, Migcampista: 5, Davanter: 2 },
    '5-4-1':  { Porter: 1, Defensa: 5, Migcampista: 4, Davanter: 1 },
    '5-3-2':  { Porter: 1, Defensa: 5, Migcampista: 3, Davanter: 2 },
}

const POS_COLORS = {
    Porter:      { bg: 'bg-yellow-400', text: 'text-yellow-900', border: 'border-yellow-300' },
    Defensa:     { bg: 'bg-blue-500',   text: 'text-blue-900',   border: 'border-blue-400'   },
    Migcampista: { bg: 'bg-green-400',  text: 'text-green-900',  border: 'border-green-400'  },
    Davanter:    { bg: 'bg-red-500',    text: 'text-red-900',    border: 'border-red-400'    },
}

function nomCurt(nom) {
    if (!nom) return ''
    const parts = nom.trim().split(' ')
    const cognom = parts[parts.length - 1]
    return cognom.length > 9 ? cognom.slice(0, 9) : cognom
}

// ── Camp read-only (fora del component principal) ───────────────
function CampEquip({ userId, teamsData, allPlayers, puntsByPlayer }) {
    const team = teamsData.find(t => t.user_id === userId)
    if (!team) return <div className="text-gray-500 text-sm text-center py-10">Sense equip configurat</div>

    const formacio    = team.formacio || '4-4-2'
    const alineacio   = team.alineacio || {}
    const formacioObj = FORMACIONS[formacio] || FORMACIONS['4-4-2']

    const titularJugadors = Object.entries(alineacio).map(([key, pid]) => ({
        key, player: allPlayers.find(p => p.id === pid)
    })).filter(x => x.player)

    function renderSlotLlegible(posicio, index) {
        const key      = `${posicio}_${index}`
        const playerId = alineacio[key]
        const jugador  = allPlayers.find(p => p.id === playerId)
        const colors   = POS_COLORS[posicio]
        const pts      = playerId ? (puntsByPlayer[playerId] ?? null) : null

        return (
            <div key={key} className="flex flex-col items-center" style={{ width: 56 }}>
                <div className={`w-12 h-12 rounded-full border-2 flex flex-col items-center justify-center
                    ${jugador ? `${colors.bg} ${colors.border}` : 'border-dashed border-white/20 bg-black/20'}`}>
                    {jugador ? (
                        <>
                            <span className={`text-[9px] font-bold ${colors.text} leading-tight text-center px-0.5`}>
                                {nomCurt(jugador.nombre)}
                            </span>
                            {pts !== null && (
                                <span className={`text-[8px] font-bold ${colors.text} opacity-80`}>{pts}p</span>
                            )}
                        </>
                    ) : (
                        <span className="text-white/20 text-lg">·</span>
                    )}
                </div>
                <span className="text-white/60 text-[9px] mt-0.5 text-center w-14 truncate">
                    {jugador ? nomCurt(jugador.nombre) : ''}
                </span>
            </div>
        )
    }

    return (
        <div>
            {/* Camp */}
            <div className="relative rounded-xl overflow-hidden mb-3"
                 style={{
                     width: '100%', maxWidth: 280, margin: '0 auto',
                     height: 380,
                     backgroundImage: `repeating-linear-gradient(180deg,rgba(255,255,255,0.04) 0px,rgba(255,255,255,0.04) 40px,transparent 40px,transparent 80px),
                     linear-gradient(180deg,#1e5c1e 0%,#246b24 14%,#1e5c1e 28%,#246b24 42%,#1e5c1e 56%,#246b24 70%,#1e5c1e 84%,#246b24 100%)`,
                     border: '2px solid #14401a',
                     boxShadow: 'inset 0 0 30px rgba(0,0,0,0.4)'
                 }}>
                <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 280 380" preserveAspectRatio="none">
                    <rect x="6" y="6" width="268" height="368" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1.5"/>
                    <line x1="6" y1="190" x2="274" y2="190" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                    <circle cx="140" cy="190" r="35" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                </svg>
                <div className="absolute inset-0 flex flex-col justify-between" style={{ padding: '14px 8px' }}>
                    <div className="flex justify-around items-center">
                        {Array.from({ length: formacioObj.Davanter }).map((_, i) => renderSlotLlegible('Davanter', i))}
                    </div>
                    <div className="flex justify-around items-center">
                        {Array.from({ length: formacioObj.Migcampista }).map((_, i) => renderSlotLlegible('Migcampista', i))}
                    </div>
                    <div className="flex justify-around items-center">
                        {Array.from({ length: formacioObj.Defensa }).map((_, i) => renderSlotLlegible('Defensa', i))}
                    </div>
                    <div className="flex justify-around items-center">
                        {Array.from({ length: formacioObj.Porter }).map((_, i) => renderSlotLlegible('Porter', i))}
                    </div>
                </div>
            </div>

            {/* Llista titulars amb punts */}
            {titularJugadors.length > 0 && (
                <div className="bg-gray-900/80 border border-gray-700 rounded-xl p-2">
                    <p className="text-gray-500 text-[10px] uppercase tracking-wider mb-1.5 font-semibold">
                        Formació: {formacio}
                    </p>
                    <div className="grid grid-cols-2 gap-1">
                        {titularJugadors.map(({ key, player }) => {
                            const colors = POS_COLORS[player.posicion]
                            const pts    = puntsByPlayer[player.id] ?? null
                            return (
                                <div key={key} className="flex items-center gap-1.5 bg-gray-800 rounded-lg px-2 py-1">
                                    <span className={`text-[8px] font-bold px-1 py-0.5 rounded-full ${colors.bg} ${colors.text}`}>
                                        {player.posicion.slice(0, 3).toUpperCase()}
                                    </span>
                                    <span className="text-white text-[10px] flex-1 truncate">{player.nombre}</span>
                                    {pts !== null && (
                                        <span className="text-green-400 text-[10px] font-bold">{pts}p</span>
                                    )}
                                </div>
                            )
                        })}
                    </div>
                </div>
            )}
        </div>
    )
}

export default function Classificacio() {
    const [ranking, setRanking]                           = useState([])
    const [loading, setLoading]                           = useState(true)
    const [tabActiva, setTabActiva]                       = useState('jornada')

    // Jornada actual
    const [jornadaActual]                                 = useState(1)
    const [rankingJornadaActual, setRankingJornadaActual] = useState([])
    const [carregantActual, setCarregantActual]           = useState(false)
    const [participantSel, setParticipantSel]             = useState(null)
    const [teamsData, setTeamsData]                       = useState([])
    const [allPlayers, setAllPlayers]                     = useState([])
    const [puntsByPlayer, setPuntsByPlayer]               = useState({})

    // Jornades passades
    const [jornadaSeleccionada, setJornadaSeleccionada]   = useState(1)
    const [rankingJornada, setRankingJornada]             = useState([])
    const [carregantJornada, setCarregantJornada]         = useState(false)

    const jornades = Array.from({ length: 38 }, (_, i) => i + 1)

    const TABS = [
        { id: 'jornada',  label: ' Jornada actual' },
        { id: 'passades', label: ' Jornades passades' },
        { id: 'general',  label: ' Classificació general' },
    ]

    // Carrega dades generals (per ranking general)
    useEffect(() => {
        let actiu = true
        async function loadRanking() {
            const { data: picks } = await supabase.from('draft_picks').select('user_id')
            const { data: perfils } = await supabase.from('profiles').select('id, nom, email')
            if (!actiu) return
            if (!picks) { setLoading(false); return }
            const comptador = {}
            picks.forEach(pick => { comptador[pick.user_id] = (comptador[pick.user_id] || 0) + 1 })
            const llista = Object.entries(comptador).map(([userId, total]) => {
                const perfil = perfils?.find(p => p.id === userId)
                return { userId, total, nom: perfil?.nom || perfil?.email || userId.slice(0, 8) + '...' }
            }).sort((a, b) => b.total - a.total)
            setRanking(llista)
            setLoading(false)
        }
        void loadRanking()
        return () => { actiu = false }
    }, [])

    // Carrega dades de la jornada actual (tab 1)
    useEffect(() => {
        if (tabActiva !== 'jornada') return
        let actiu = true
        async function loadActual() {
            setCarregantActual(true)
            const [{ data: punts }, { data: teams }, { data: perfils }, { data: playersAll }] = await Promise.all([
                supabase.from('player_punts').select('player_id, punts').eq('jornada', jornadaActual),
                supabase.from('teams').select('user_id, alineacio, formacio'),
                supabase.from('profiles').select('id, nom, email'),
                supabase.from('players').select('*'),
            ])
            if (!actiu) return

            setAllPlayers(playersAll || [])
            setTeamsData(teams || [])

            const mapa = {}
            punts?.forEach(p => { mapa[p.player_id] = Number(p.punts) })
            setPuntsByPlayer(mapa)

            const calc = (teams || []).map(team => {
                const alineacio = team.alineacio || {}
                const totalPunts = Object.values(alineacio).reduce((sum, pid) => sum + (mapa[pid] || 0), 0)
                const perfil = perfils?.find(p => p.id === team.user_id)
                return { userId: team.user_id, nom: perfil?.nom || perfil?.email || '...', punts: totalPunts }
            }).sort((a, b) => b.punts - a.punts)

            setRankingJornadaActual(calc)
            if (calc.length > 0) setParticipantSel(sel => sel ?? calc[0].userId)
            setCarregantActual(false)
        }
        void loadActual()
        return () => { actiu = false }
    }, [tabActiva, jornadaActual])

    // Carrega ranking d'una jornada passada (tab 2)
    useEffect(() => {
        if (tabActiva !== 'passades') return
        let actiu = true
        async function loadJornada() {
            setCarregantJornada(true)
            setRankingJornada([])
            const [{ data: punts }, { data: teams }, { data: perfils }] = await Promise.all([
                supabase.from('player_punts').select('player_id, punts').eq('jornada', jornadaSeleccionada),
                supabase.from('teams').select('user_id, alineacio'),
                supabase.from('profiles').select('id, nom, email'),
            ])
            if (!actiu) return
            if (!punts?.length || !teams?.length) { setRankingJornada([]); setCarregantJornada(false); return }
            const puntsMapa = {}
            punts.forEach(p => { puntsMapa[p.player_id] = Number(p.punts) })
            const rankingCalculat = teams.map(team => {
                const alineacio = team.alineacio || {}
                const totalPunts = Object.values(alineacio).reduce((sum, pid) => sum + (puntsMapa[pid] || 0), 0)
                const perfil = perfils?.find(p => p.id === team.user_id)
                return { userId: team.user_id, nom: perfil?.nom || perfil?.email || '...', punts: totalPunts }
            }).sort((a, b) => b.punts - a.punts)
            setRankingJornada(rankingCalculat)
            setCarregantJornada(false)
        }
        void loadJornada()
        return () => { actiu = false }
    }, [jornadaSeleccionada, tabActiva])

    // ── Render ──────────────────────────────────────────────────────
    if (loading) return (
        <>
            <Navbar />
            <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">Carregant...</div>
        </>
    )

    return (
        <>
            <Navbar />
            <main className="min-h-screen bg-gray-950 text-white p-4 md:p-6">
                <div className="max-w-6xl mx-auto">

                    {/* Capçalera */}
                    <div className="flex justify-between items-center mb-6">
                        <h1 className="text-2xl font-bold text-green-400"> Classificació</h1>
                        <Link href="/draft" className="bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg text-sm transition">
                            Anar al Draft
                        </Link>
                    </div>

                    {/* Botons de tab */}
                    <div className="flex rounded-xl overflow-hidden border border-gray-700 mb-6">
                        {TABS.map((tab, i) => (
                            <button key={tab.id} onClick={() => setTabActiva(tab.id)}
                                    className={`flex-1 py-2.5 px-2 text-xs md:text-sm font-semibold transition
                                        ${tabActiva === tab.id ? 'bg-green-500 text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-800'}
                                        ${i > 0 ? 'border-l border-gray-700' : ''}`}>
                                {tab.label}
                            </button>
                        ))}
                    </div>

                    {/* ── TAB 1: Jornada actual ── */}
                    {tabActiva === 'jornada' && (
                        <section>
                            <p className="text-gray-400 text-sm mb-4">Jornada {jornadaActual}</p>
                            {carregantActual ? (
                                <p className="text-gray-500 text-center py-12 animate-pulse">Carregant...</p>
                            ) : (
                                <div className="flex gap-4 items-start flex-col lg:flex-row">

                                    {/* ESQUERRA: Ranking */}
                                    <div className="w-full lg:w-72 flex-shrink-0">
                                        <p className="text-gray-400 text-xs uppercase tracking-wider font-semibold mb-2">Classificació</p>
                                        {rankingJornadaActual.length === 0 ? (
                                            <p className="text-gray-500 text-sm text-center py-8 bg-gray-900 border border-gray-800 rounded-xl">
                                                Sense puntuacions per la jornada {jornadaActual}
                                            </p>
                                        ) : (
                                            <div className="space-y-1.5">
                                                {rankingJornadaActual.map((p, i) => {
                                                    const esSel = participantSel === p.userId
                                                    const medalles = ['', '', '']
                                                    return (
                                                        <button key={p.userId} onClick={() => setParticipantSel(p.userId)}
                                                                className={`w-full flex items-center gap-3 rounded-xl px-3 py-2.5 transition border text-left
                                                                    ${esSel
                                                                        ? 'bg-green-500/20 border-green-500 shadow-lg shadow-green-900/30'
                                                                        : 'bg-gray-900 border-gray-800 hover:bg-gray-800'}`}>
                                                            <div className="text-base w-8 text-center font-bold">
                                                                {i < 3 ? medalles[i] : <span className="text-gray-400 text-sm">{i + 1}</span>}
                                                            </div>
                                                            <div className="flex-1 min-w-0">
                                                                <div className={`font-semibold truncate text-sm ${esSel ? 'text-green-300' : 'text-white'}`}>
                                                                    {p.nom}
                                                                </div>
                                                            </div>
                                                            <div className={`font-bold text-sm ${esSel ? 'text-green-300' : 'text-green-400'}`}>
                                                                {p.punts} pts
                                                            </div>
                                                        </button>
                                                    )
                                                })}
                                            </div>
                                        )}
                                    </div>

                                    {/* DRETA: Camp de l'equip seleccionat */}
                                    <div className="flex-1 min-w-0">
                                        {participantSel ? (
                                            <>
                                                <p className="text-gray-400 text-xs uppercase tracking-wider font-semibold mb-2">
                                                    Equip de {rankingJornadaActual.find(p => p.userId === participantSel)?.nom}
                                                </p>
                                                <CampEquip
                                                    userId={participantSel}
                                                    teamsData={teamsData}
                                                    allPlayers={allPlayers}
                                                    puntsByPlayer={puntsByPlayer}
                                                />
                                            </>
                                        ) : (
                                            <p className="text-gray-600 text-sm text-center py-12">
                                                Selecciona un participant per veure el seu equip
                                            </p>
                                        )}
                                    </div>

                                </div>
                            )}
                        </section>
                    )}

                    {/* ── TAB 2: Jornades passades ── */}
                    {tabActiva === 'passades' && (
                        <section className="max-w-2xl">
                            <p className="text-gray-400 text-sm mb-3">Selecciona una jornada:</p>
                            <div className="grid grid-cols-7 md:grid-cols-10 gap-1.5 mb-5">
                                {jornades.map(j => (
                                    <button key={j} onClick={() => setJornadaSeleccionada(j)}
                                            className={`text-xs rounded-lg py-1.5 border transition font-mono
                                                ${jornadaSeleccionada === j
                                                    ? 'bg-green-500 border-green-400 text-white font-bold'
                                                    : 'bg-gray-800 border-gray-700 text-gray-300 hover:bg-gray-700'}`}>
                                        {j}
                                    </button>
                                ))}
                            </div>
                            <div className="bg-gray-900 border border-gray-800 rounded-xl p-4">
                                <p className="text-white font-semibold mb-3">Classificació — Jornada {jornadaSeleccionada}</p>
                                {carregantJornada ? (
                                    <p className="text-gray-500 text-sm text-center py-6 animate-pulse">Carregant...</p>
                                ) : rankingJornada.length === 0 ? (
                                    <p className="text-gray-500 text-sm text-center py-6">
                                        Encara no hi ha puntuacions per la jornada {jornadaSeleccionada}.
                                    </p>
                                ) : (
                                    <div className="space-y-2">
                                        {rankingJornada.map((p, i) => (
                                            <div key={p.userId} className="flex items-center gap-3 bg-gray-950/70 border border-gray-800 rounded-lg p-3">
                                                <div className="text-lg w-9 text-center font-bold">
                                                    {i < 3 ? ['','',''][i] : <span className="text-gray-400 text-sm">{i + 1}</span>}
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <div className="font-semibold text-white truncate">{p.nom}</div>
                                                </div>
                                                <div className="text-green-400 font-bold">{p.punts} pts</div>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </section>
                    )}

                    {/* ── TAB 3: Classificació general ── */}
                    {tabActiva === 'general' && (
                        <section className="max-w-2xl">
                            <p className="text-gray-400 text-sm mb-4">Acumulat de tota la temporada</p>
                            {ranking.length === 0 ? (
                                <p className="text-gray-500 text-center py-12">Encara no hi ha dades generals.</p>
                            ) : (
                                <div className="space-y-2">
                                    {ranking.map((p, i) => (
                                        <div key={p.userId} className="flex items-center gap-3 bg-gray-900 border border-gray-800 rounded-lg p-3">
                                            <div className="text-lg w-9 text-center font-bold">
                                                {i < 3 ? ['','',''][i] : <span className="text-gray-400 text-sm">{i + 1}</span>}
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="font-semibold text-white truncate">{p.nom}</div>
                                                <div className="text-gray-500 text-xs">{p.total} jugadors triats</div>
                                            </div>
                                            <div className="text-green-400 font-bold">0 pts</div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </section>
                    )}

                </div>
            </main>
        </>
    )
}

