'use client'
import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '../../lib/supabase'

export default function Draft() {
    const [players, setPlayers] = useState([])
    const [picks, setPicks] = useState([])
    const [meusPicks, setMeusPicks] = useState([])
    const [user, setUser] = useState(null)
    const [loading, setLoading] = useState(true)
    const [draft, setDraft] = useState(null)
    const [participants, setParticipants] = useState([])
    const router = useRouter()

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) router.push('/login')
            else {
                setUser(data.user)
                guardarPerfil(data.user)
                fetchTot(data.user.id)
            }
        })

        // Escolta canvis en temps real
        const canal = supabase.channel('draft-canal')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'draft_picks' }, () => {
                supabase.auth.getUser().then(({ data }) => fetchPicks(data.user?.id))
            })
            .on('postgres_changes', { event: '*', schema: 'public', table: 'drafts' }, () => {
                fetchDraft()
            })
            .subscribe()

        return () => supabase.removeChannel(canal)
    }, [])

    async function guardarPerfil(user) {
        const { data } = await supabase.from('profiles').select('id').eq('id', user.id).single()
        if (!data) {
            await supabase.from('profiles').insert({
                id: user.id,
                email: user.email,
                nom: user.user_metadata?.full_name || user.email.split('@')[0]
            })
        }
    }

    async function fetchTot(userId) {
        await Promise.all([fetchPlayers(), fetchPicks(userId), fetchDraft(), fetchParticipants()])
        setLoading(false)
    }

    async function fetchPlayers() {
        const { data } = await supabase.from('players').select('*').order('valor', { ascending: false })
        setPlayers(data || [])
    }

    async function fetchPicks(userId) {
        const { data } = await supabase.from('draft_picks').select('player_id, user_id')
        setPicks(data?.map(p => p.player_id) || [])
        if (userId) setMeusPicks(data?.filter(p => p.user_id === userId).map(p => p.player_id) || [])
    }

    async function fetchDraft() {
        const { data } = await supabase.from('drafts').select('*').single()
        setDraft(data)
    }

    async function fetchParticipants() {
        const { data } = await supabase.from('profiles').select('id, nom, email')
        setParticipants(data || [])
    }

    async function unirseAlDraft() {
        if (!draft || !user) return
        const ordre = draft.ordre_participants || []
        if (ordre.includes(user.id)) return
        const nouOrdre = [...ordre, user.id]
        await supabase.from('drafts').update({ ordre_participants: nouOrdre }).eq('id', draft.id)
        fetchDraft()
    }

    async function iniciarDraft() {
        if (!draft) return
        const ordre = draft.ordre_participants || []
        if (ordre.length < 2) return alert('Necessites almenys 2 participants!')
        await supabase.from('drafts').update({ estat: 'actiu', torn_actual: 0 }).eq('id', draft.id)
    }

    async function pickPlayer(playerId) {
        if (!user || !draft) return
        const ordre = draft.ordre_participants || []
        const tornIndex = draft.torn_actual % ordre.length

        // Calcula el següent torn (serpentina)
        const rondaActual = Math.floor(draft.torn_actual / ordre.length)
        const esRondaParell = rondaActual % 2 === 0
        const ordenat = esRondaParell ? ordre : [...ordre].reverse()
        const posicioActual = draft.torn_actual % ordre.length
        const posicioSeguent = (posicioActual + 1) % ordre.length
        const seguentUserId = ordenat[posicioSeguent]

        // Guarda el pick
        await supabase.from('draft_picks').insert({
            player_id: playerId,
            user_id: user.id,
            torn: draft.torn_actual
        })

        // Actualitza el torn
        await supabase.from('drafts').update({ torn_actual: draft.torn_actual + 1 }).eq('id', draft.id)

        // Envia email al següent
        const seguent = participants.find(p => p.id === seguentUserId)
        if (seguent?.email) {
            await fetch('/api/notify-torn', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    email: seguent.email,
                    nom: seguent.nom || seguent.email,
                    torn: draft.torn_actual + 2,
                    jugadorsTriats: picks.length + 1
                })
            })
        }
    }

    const ordre = draft?.ordre_participants || []
    const tornIndex = draft ? draft.torn_actual % ordre.length : 0
    const userActual = ordre[tornIndex]
    const esMeuTorn = userActual === user?.id
    const nomActual = participants.find(p => p.id === userActual)?.nom || '...'

    const posicions = ['Porter', 'Defensa', 'Migcampista', 'Davanter']
    const jaEstic = ordre.includes(user?.id)

    if (loading) return (
        <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">
            Carregant...
        </div>
    )

    return (
        <main className="min-h-screen bg-gray-950 text-white p-8">
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h1 className="text-3xl font-bold text-green-400">⚽ Sala de Draft</h1>
                    <p className="text-gray-400">Hola, {user?.email} · {meusPicks.length} jugadors triats</p>
                </div>
                <button
                    onClick={() => { supabase.auth.signOut(); router.push('/login') }}
                    className="bg-gray-700 hover:bg-gray-600 px-4 py-2 rounded-lg text-sm transition"
                >
                    Sortir
                </button>
            </div>

            {/* Panel d'estat del draft */}
            <div className="bg-gray-900 border border-gray-700 rounded-xl p-5 mb-8">
                {draft?.estat === 'pendent' && (
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-white font-semibold text-lg">Draft pendent d'iniciar</p>
                            <p className="text-gray-400 text-sm">{ordre.length} participants apuntats</p>
                            <div className="flex flex-wrap gap-2 mt-2">
                                {ordre.map(uid => (
                                    <span key={uid} className="bg-gray-700 text-gray-300 text-xs px-3 py-1 rounded-full">
                    {participants.find(p => p.id === uid)?.nom || uid.slice(0,8)}
                  </span>
                                ))}
                            </div>
                        </div>
                        <div className="flex flex-col gap-2">
                            {!jaEstic && (
                                <button onClick={unirseAlDraft} className="bg-green-500 hover:bg-green-600 px-5 py-2 rounded-lg font-semibold transition">
                                    Apuntar-me
                                </button>
                            )}
                            {jaEstic && ordre.length >= 2 && (
                                <button onClick={iniciarDraft} className="bg-blue-500 hover:bg-blue-600 px-5 py-2 rounded-lg font-semibold transition">
                                    Iniciar Draft
                                </button>
                            )}
                            {jaEstic && ordre.length < 2 && (
                                <p className="text-gray-500 text-sm">Esperant més participants...</p>
                            )}
                        </div>
                    </div>
                )}

                {draft?.estat === 'actiu' && (
                    <div className="text-center">
                        <p className="text-gray-400 text-sm mb-1">Torn {draft.torn_actual + 1}</p>
                        {esMeuTorn ? (
                            <p className="text-green-400 text-xl font-bold"> És el teu torn! Tria un jugador</p>
                        ) : (
                            <p className="text-white text-xl font-semibold">⏳ Torn de <span className="text-yellow-400">{nomActual}</span></p>
                        )}
                    </div>
                )}
            </div>

            {/* Llista de jugadors */}
            {draft?.estat === 'actiu' && posicions.map(pos => (
                <div key={pos} className="mb-8">
                    <h2 className="text-xl font-semibold text-white mb-3 border-b border-gray-700 pb-2">{pos}s</h2>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                        {players.filter(p => p.posicion === pos).map(player => {
                            const agafat = picks.includes(player.id)
                            const meu = meusPicks.includes(player.id)
                            return (
                                <button
                                    key={player.id}
                                    onClick={() => !agafat && esMeuTorn && pickPlayer(player.id)}
                                    disabled={agafat || !esMeuTorn}
                                    className={`p-4 rounded-lg text-left transition border ${
                                        meu
                                            ? 'bg-green-900 border-green-500'
                                            : agafat
                                                ? 'bg-gray-800 opacity-40 cursor-not-allowed border-gray-700'
                                                : esMeuTorn
                                                    ? 'bg-gray-800 hover:bg-green-900 hover:border-green-500 border-gray-700 cursor-pointer'
                                                    : 'bg-gray-800 border-gray-700 opacity-60 cursor-not-allowed'
                                    }`}
                                >
                                    <div className="font-semibold">{player.nombre}</div>
                                    <div className="text-sm text-gray-400">{player.equipo_real}</div>
                                    <div className="text-yellow-400 text-sm mt-1">{'⭐'.repeat(player.valor - 6)}</div>
                                    {meu && <div className="text-green-400 text-xs mt-1">✓ El teu</div>}
                                    {agafat && !meu && <div className="text-red-400 text-xs mt-1">Agafat</div>}
                                </button>
                            )
                        })}
                    </div>
                </div>
            ))}

            {draft?.estat === 'pendent' && (
                <p className="text-gray-600 text-center mt-20">Els jugadors apareixeran quan s'iniciï el draft</p>
            )}
        </main>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '../../lib/supabase'
import Navbar from '../components/Navbar'

const POS_COLORS = {
    Porter:      { bg: 'bg-yellow-500', text: 'text-yellow-900' },
    Defensa:     { bg: 'bg-blue-500',   text: 'text-blue-900'   },
    Migcampista: { bg: 'bg-green-500',  text: 'text-green-900'  },
    Davanter:    { bg: 'bg-red-500',    text: 'text-red-900'    },
}

export default function Draft() {
    const [players, setPlayers]           = useState([])
    const [picks, setPicks]               = useState([])         // [player_id]
    const [picksDetall, setPicksDetall]   = useState([])         // [{player_id, user_id}]
    const [meusPicks, setMeusPicks]       = useState([])
    const [user, setUser]                 = useState(null)
    const [loading, setLoading]           = useState(true)
    const [draft, setDraft]               = useState(null)
    const [participants, setParticipants] = useState([])
    const [cerca, setCerca]               = useState('')
    const [posicioFiltro, setPosicioFiltro] = useState('Tots')
    const [ordenar, setOrdenar]           = useState('posicio')  // 'posicio' | 'preu' | 'punts'
    const [jugadorPreSel, setJugadorPreSel] = useState(null)
    const [confirmant, setConfirmant]       = useState(false)
    const [puntsByPlayer, setPuntsByPlayer] = useState({})     // {playerId: [{jornada, punts}]} — darreres 5
    const router = useRouter()

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) router.push('/login')
            else { setUser(data.user); guardarPerfil(data.user); fetchTot(data.user.id) }
        })

        const canal = supabase.channel('draft-canal')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'draft_picks' }, () => {
                supabase.auth.getUser().then(({ data }) => fetchPicks(data.user?.id))
            })
            .on('postgres_changes', { event: '*', schema: 'public', table: 'drafts' }, () => {
                fetchDraft()
            })
            .subscribe()

        return () => supabase.removeChannel(canal)
    }, [])

    async function guardarPerfil(u) {
        const { data } = await supabase.from('profiles').select('id').eq('id', u.id).single()
        if (!data) {
            await supabase.from('profiles').insert({
                id: u.id, email: u.email,
                nom: u.user_metadata?.full_name || u.email.split('@')[0]
            })
        }
    }

    async function fetchTot(userId) {
        await Promise.all([fetchPlayers(), fetchPicks(userId), fetchDraft(), fetchParticipants(), fetchPuntsJornades()])
        setLoading(false)
    }

    async function fetchPlayers() {
        const { data } = await supabase.from('players').select('*').order('posicion').order('nombre')
        setPlayers(data || [])
    }

    async function fetchPuntsJornades() {
        const { data } = await supabase
            .from('player_punts')
            .select('player_id, jornada, punts')
            .order('jornada', { ascending: false })
        const mapa = {}
        data?.forEach(p => {
            if (!mapa[p.player_id]) mapa[p.player_id] = []
            if (mapa[p.player_id].length < 5) mapa[p.player_id].push({ jornada: p.jornada, punts: p.punts })
        })
        // Mostrar de més antiga a més recent
        Object.keys(mapa).forEach(k => { mapa[k] = mapa[k].reverse() })
        setPuntsByPlayer(mapa)
    }

    async function fetchPicks(userId) {
        const { data } = await supabase.from('draft_picks').select('player_id, user_id')
        setPicksDetall(data || [])
        setPicks(data?.map(p => p.player_id) || [])
        if (userId) setMeusPicks(data?.filter(p => p.user_id === userId).map(p => p.player_id) || [])
    }

    async function fetchDraft() {
        const { data } = await supabase.from('drafts').select('*').single()
        setDraft(data)
    }

    async function fetchParticipants() {
        const { data } = await supabase.from('profiles').select('id, nom, email')
        setParticipants(data || [])
    }

    async function unirseAlDraft() {
        if (!draft || !user) return
        const ordre = draft.ordre_participants || []
        if (ordre.includes(user.id)) return
        const nouOrdre = [...ordre, user.id]
        await supabase.from('drafts').update({ ordre_participants: nouOrdre }).eq('id', draft.id)
        fetchDraft()
    }

    async function pickPlayer(playerId) {
        if (!user || !draft || !esMeuTorn) return
        const playerData = players.find(p => p.id === playerId)

        // Validació límit equip real
        if (playerData && maxEquip < 999) {
            const comptActual = meusDeEquipReal(playerData.equipo_real)
            if (comptActual >= maxEquip) {
                alert(`Ja tens ${comptActual} jugadors de ${playerData.equipo_real}. Màxim permès: ${maxEquip}`)
                setJugadorPreSel(null)
                setConfirmant(false)
                return
            }
        }

        // Validació límit per posició
        if (playerData) {
            const maxPos   = LIMIT_POSICIO[playerData.posicion] ?? 99
            const comptPos = meusDePos(playerData.posicion)
            if (comptPos >= maxPos) {
                alert(`Ja tens ${comptPos} ${playerData.posicion}s. Màxim permès: ${maxPos}`)
                setJugadorPreSel(null)
                setConfirmant(false)
                return
            }
        }
        setConfirmant(true)
        const ordre = draft.ordre_participants || []
        const ronda = Math.floor(draft.torn_actual / ordre.length)
        const esParell = ronda % 2 === 0
        const ordenat = esParell ? ordre : [...ordre].reverse()
        const posActual = draft.torn_actual % ordre.length
        const posSeguent = (posActual + 1) % ordre.length
        const seguentUserId = ordenat[posSeguent]

        await supabase.from('draft_picks').insert({ player_id: playerId, user_id: user.id, torn: draft.torn_actual })
        await supabase.from('drafts').update({ torn_actual: draft.torn_actual + 1 }).eq('id', draft.id)

        const seguent = participants.find(p => p.id === seguentUserId)
        if (seguent?.email) {
            await fetch('/api/notify-torn', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    email: seguent.email, nom: seguent.nom || seguent.email,
                    torn: draft.torn_actual + 2, jugadorsTriats: picks.length + 1
                })
            })
        }
        setJugadorPreSel(null)
        setConfirmant(false)
    }

    // ── Derived state ────────────────────────────────────────────────
    const ordre = draft?.ordre_participants || []
    const n = ordre.length || 1
    const rondaActual = draft ? Math.floor(draft.torn_actual / n) : 0
    const ordenatActual = rondaActual % 2 === 0 ? ordre : [...ordre].reverse()
    const posActual = draft ? draft.torn_actual % n : 0
    const userActual = ordenatActual[posActual]
    const esMeuTorn = userActual === user?.id
    const nomActual = participants.find(p => p.id === userActual)?.nom || '...'
    const jaEstic = ordre.includes(user?.id)

    function propietari(playerId) {
        const pick = picksDetall.find(p => p.player_id === playerId)
        if (!pick) return null
        const part = participants.find(p => p.id === pick.user_id)
        return part?.nom || part?.email?.split('@')[0] || '?'
    }

    // Genera llista de torns per al panell dret
    function generarTorns() {
        if (!ordre.length || !draft) return []
        const total = draft.max_jugadors * ordre.length
        const result = []
        const inici = Math.max(0, draft.torn_actual - 3)
        const fi = Math.min(total, draft.torn_actual + 15)
        for (let t = inici; t < fi; t++) {
            const r = Math.floor(t / n)
            const ord = r % 2 === 0 ? ordre : [...ordre].reverse()
            const uid = ord[t % n]
            const part = participants.find(p => p.id === uid)
            result.push({
                t, uid,
                nom: part?.nom || part?.email?.split('@')[0] || '...',
                esCurrent: t === draft.torn_actual,
                esPassat: t < draft.torn_actual,
                esMeu: uid === user?.id,
            })
        }
        return result
    }

    // Filtre jugadors
    const maxEquip = draft?.max_jugadors_equip || 999  // límit per equip real

    // Límits per posició (fixes de la lliga)
    const LIMIT_POSICIO = { Porter: 2, Defensa: 6, Migcampista: 6, Davanter: 4 }

    // Compte quants jugadors meus hi ha per cada equip real
    function meusDeEquipReal(equipReal) {
        return meusPicks.filter(pid => {
            const p = players.find(pl => pl.id === pid)
            return p?.equipo_real === equipReal
        }).length
    }

    // Compte quants jugadors meus per posició
    function meusDePos(posicio) {
        return meusPicks.filter(pid => {
            const p = players.find(pl => pl.id === pid)
            return p?.posicion === posicio
        }).length
    }

    const posicions = ['Porter', 'Defensa', 'Migcampista', 'Davanter']
    const jugadorsFiltrats = players
        .filter(p => {
            const okCerca = cerca === '' || p.nombre.toLowerCase().includes(cerca.toLowerCase()) ||
                (p.equipo_real || '').toLowerCase().includes(cerca.toLowerCase())
            const okPos = posicioFiltro === 'Tots' || p.posicion === posicioFiltro
            return okCerca && okPos
        })
        .sort((a, b) => {
            if (ordenar === 'preu')  return (b.precio || 0) - (a.precio || 0)
            if (ordenar === 'punts') return (b.punts_totals || 0) - (a.punts_totals || 0)
            return 0  // 'posicio': l'agrupació ja gestiona l'ordre
        })

    // ── Format preu ─────────────────────────────────────────────────
    function formatPreu(precio) {
        if (!precio) return '—'
        if (precio >= 1_000_000) return (precio / 1_000_000).toFixed(1) + 'M'
        if (precio >= 1_000)     return Math.round(precio / 1_000) + 'K'
        return precio.toString()
    }

    // ── Targeta jugador reutilitzable ────────────────────────────────
    function renderCard(player, { agafat, meu, owner, comptEquip, limitEquip, limitPosicio, pot, colors }) {
        const jornadesJugador = puntsByPlayer[player.id] || []
        const maxPos = LIMIT_POSICIO[player.posicion] ?? 99
        const comptPos = meusDePos(player.posicion)
        return (
            <button
                key={player.id}
                onClick={() => pot && setJugadorPreSel(jugadorPreSel?.id === player.id ? null : player)}
                disabled={agafat || !esMeuTorn || limitEquip || limitPosicio}
                className={`p-3 rounded-xl text-left transition border relative overflow-hidden w-full
                    ${meu
                        ? 'bg-green-900/60 border-green-500'
                        : agafat
                            ? 'bg-gray-900 border-gray-800 opacity-50 cursor-not-allowed'
                            : limitEquip || limitPosicio
                                ? 'bg-orange-950/40 border-orange-900 opacity-60 cursor-not-allowed'
                                : jugadorPreSel?.id === player.id
                                    ? 'bg-green-700/60 border-green-400 ring-2 ring-green-400 scale-[1.02]'
                                    : pot
                                        ? 'bg-gray-800 hover:bg-green-900/40 hover:border-green-500 border-gray-700 cursor-pointer hover:scale-[1.02]'
                                        : 'bg-gray-900 border-gray-800 cursor-not-allowed opacity-70'
                    }`}
            >
                {/* Foto + nom + equip */}
                <div className="flex items-center gap-3 mb-2">
                    {/* Foto jugador: fallback inicial si la imatge no carrega */}
                    <div className="relative w-12 h-12 flex-shrink-0">
                        <div className={`w-12 h-12 rounded-full flex items-center justify-center text-sm font-bold ${colors.bg} ${colors.text}`}>
                            {player.nombre?.charAt(0)}
                        </div>
                        {player.foto && (
                            <img
                                src={player.foto}
                                alt={player.nombre}
                                className="w-12 h-12 rounded-full object-cover absolute inset-0"
                                onError={e => { e.target.style.display = 'none' }}
                            />
                        )}
                    </div>
                    <div className="min-w-0 flex-1">
                        <div className="font-bold text-sm text-white truncate">{player.nombre}</div>
                        <div className="flex items-center gap-1 text-gray-400 text-xs truncate">
                            {player.escudo_equip && (
                                <img src={player.escudo_equip} alt=""
                                     className="w-4 h-4 object-contain flex-shrink-0"
                                     onError={e => { e.target.style.display = 'none' }} />
                            )}
                            {player.equipo_real}
                        </div>
                    </div>
                </div>

                {/* Preu i punts */}
                <div className="flex items-center justify-between mb-2">
                    <div className="text-center">
                        <div className="text-green-400 font-bold text-sm">{formatPreu(player.precio)}</div>
                        <div className="text-gray-600 text-[9px] uppercase">Preu</div>
                    </div>
                    <div className="w-px h-6 bg-gray-700" />
                    <div className="text-center">
                        <div className="text-yellow-400 font-bold text-sm">{player.punts_totals || 0}</div>
                        <div className="text-gray-600 text-[9px] uppercase">Punts</div>
                    </div>
                    <div className="w-px h-6 bg-gray-700" />
                    <div className="text-center">
                        <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full ${colors.bg} ${colors.text}`}>
                            {player.posicion?.slice(0, 3).toUpperCase()}
                        </span>
                    </div>
                </div>

                {/* Darreres 5 jornades */}
                {jornadesJugador.length > 0 && (
                    <div className="border-t border-gray-700/50 pt-2">
                        <div className="text-gray-600 text-[8px] uppercase tracking-wider mb-1">Darreres jornades</div>
                        <div className="flex gap-1">
                            {jornadesJugador.map(({ jornada, punts: p }) => (
                                <div key={jornada} className="flex-1 text-center bg-gray-900/60 rounded py-0.5">
                                    <div className={`text-[11px] font-bold leading-tight ${
                                        p >= 8  ? 'text-green-400' :
                                        p >= 4  ? 'text-yellow-400' :
                                        p > 0   ? 'text-gray-300' :
                                        p < 0   ? 'text-red-400' : 'text-gray-600'
                                    }`}>{p}</div>
                                    <div className="text-gray-700 text-[7px]">J{jornada}</div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Estat */}
                {meu && <div className="mt-2 text-[10px] font-bold text-green-400">✓ El teu</div>}
                {agafat && !meu && <div className="mt-2 text-[10px] text-gray-400 truncate"> {owner}</div>}
                {limitPosicio && !agafat && !meu && (
                    <div className="mt-2 text-[10px] text-orange-400"> Màx. {maxPos} {player.posicion}s ({comptPos}/{maxPos})</div>
                )}
                {limitEquip && !agafat && !limitPosicio && (
                    <div className="mt-2 text-[10px] text-orange-400"> Límit {comptEquip}/{maxEquip} de l&apos;equip</div>
                )}
                {!agafat && !limitEquip && !limitPosicio && esMeuTorn && comptEquip > 0 && (
                    <div className="mt-2 text-[10px] text-gray-500">{comptEquip}/{maxEquip} d&apos;aquest equip</div>
                )}
                {pot && jugadorPreSel?.id !== player.id && (
                    <div className="absolute inset-0 rounded-xl ring-2 ring-green-500/0 hover:ring-green-500/50 transition pointer-events-none" />
                )}
            </button>
        )
    }

    // ── Loading ──────────────────────────────────────────────────────
    if (loading) return (
        <>
            <Navbar />
            <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">Carregant...</div>
        </>
    )

    // ── Render ───────────────────────────────────────────────────────
    return (
        <>
            <Navbar />
            <main className="min-h-screen bg-gray-950 text-white p-4 md:p-6">
                <div className="max-w-7xl mx-auto">

                    {/* Capçalera */}
                    <div className="flex justify-between items-center mb-5">
                        <div>
                            <h1 className="text-2xl font-bold text-green-400">⚽ Sala de Draft</h1>
                            <p className="text-gray-400 text-sm">
                                {participants.find(p => p.id === user?.id)?.nom || user?.email}
                                {' · '}{meusPicks.length} jugadors triats
                            </p>
                        </div>
                    </div>

                    {/* ── Banner estat (pendent o torn actual) ── */}
                    {draft?.estat === 'pendent' ? (
                        <div className="bg-gray-900 border border-yellow-700/50 rounded-xl p-3 mb-5 text-center">
                            <p className="text-yellow-400 font-semibold text-sm">⏳ El draft encara no ha començat — pots explorar els jugadors disponibles</p>
                        </div>
                    ) : draft?.estat === 'actiu' ? (
                        <div className={`rounded-xl p-3 mb-5 text-center border ${
                            esMeuTorn ? 'bg-green-900/50 border-green-500 animate-pulse' : 'bg-gray-900 border-gray-700'
                        }`}>
                            <p className="text-xs text-gray-400 mb-0.5">Torn {draft.torn_actual + 1}</p>
                            {esMeuTorn ? (
                                <p className="text-green-300 font-bold text-lg"> És el teu torn! Cerca i tria un jugador</p>
                            ) : (
                                <p className="text-white font-semibold">
                                    ⏳ Esperant que <span className="text-yellow-400">{nomActual}</span> triï...
                                </p>
                            )}
                        </div>
                    ) : null}

                    {/* ── Layout principal: jugadors + panell ordre ── */}
                    {(draft?.estat === 'pendent' || draft?.estat === 'actiu') && (
                        <div className="flex gap-5 items-start flex-col xl:flex-row">

                                {/* ── ESQUERRA: Jugadors ── */}
                                <div className="flex-1 min-w-0">

                                    {/* ── Comptador posicions del meu equip ── */}
                                {meusPicks.length > 0 && (
                                    <div className="flex gap-2 mb-3">
                                        {posicions.map(pos => {
                                            const actual  = meusDePos(pos)
                                            const max     = LIMIT_POSICIO[pos]
                                            const ple     = actual >= max
                                            const colors  = POS_COLORS[pos]
                                            return (
                                                <div key={pos} className={`flex-1 text-center rounded-lg py-1.5 border transition ${
                                                    ple ? 'bg-red-900/40 border-red-600' : actual > 0 ? `border-gray-600 bg-gray-800` : 'border-gray-700 bg-gray-900'
                                                }`}>
                                                    <div className={`text-sm font-bold ${ple ? 'text-red-400' : actual > 0 ? 'text-white' : 'text-gray-600'}`}>
                                                        {actual}<span className="text-gray-600 text-xs">/{max}</span>
                                                    </div>
                                                    <div className={`text-[9px] font-semibold ${colors.bg.replace('bg-','text-').replace('-500','-400').replace('-400','-400')}`}>
                                                        {pos.slice(0,3).toUpperCase()}
                                                    </div>
                                                    {ple && <div className="text-[8px] text-red-500 leading-tight">MÀXIM</div>}
                                                </div>
                                            )
                                        })}
                                    </div>
                                )}

                                {/* Barra cerca + filtres + ordenació */}
                                    <div className="flex flex-col gap-2 mb-4">
                                        <input
                                            type="text"
                                            placeholder=" Cercar jugador o equip..."
                                            value={cerca}
                                            onChange={e => setCerca(e.target.value)}
                                            className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-2.5 text-white text-sm placeholder-gray-500 focus:outline-none focus:border-green-500"
                                        />
                                        <div className="flex gap-2 flex-wrap">
                                            {/* Filtre posició */}
                                            <div className="flex gap-1">
                                                {['Tots', ...posicions].map(pos => (
                                                    <button key={pos} onClick={() => setPosicioFiltro(pos)}
                                                            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition
                                                                ${posicioFiltro === pos
                                                                    ? 'bg-green-500 text-white'
                                                                    : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                                                        {pos === 'Tots' ? 'Tots' : pos.slice(0, 3).toUpperCase()}
                                                    </button>
                                                ))}
                                            </div>
                                            {/* Ordenació */}
                                            <div className="flex gap-1 ml-auto">
                                                <span className="text-gray-600 text-xs self-center mr-1">Ordenar:</span>
                                                {[
                                                    { id: 'posicio', label: 'Posició' },
                                                    { id: 'preu',    label: ' Preu' },
                                                    { id: 'punts',   label: ' Punts' },
                                                ].map(o => (
                                                    <button key={o.id} onClick={() => setOrdenar(o.id)}
                                                            className={`px-3 py-1.5 rounded-lg text-xs font-bold transition
                                                                ${ordenar === o.id
                                                                    ? 'bg-blue-600 text-white'
                                                                    : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                                                        {o.label}
                                                    </button>
                                                ))}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Llista de jugadors */}
                                    {jugadorsFiltrats.length === 0 ? (
                                        <p className="text-gray-500 text-center py-10">Sense resultats per &ldquo;{cerca}&rdquo;</p>
                                    ) : ordenar !== 'posicio' ? (
                                        /* Vista plana ordenada per preu o punts */
                                        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 xl:grid-cols-3 2xl:grid-cols-4 gap-3">
                                            {jugadorsFiltrats.map(player => {
                                                const agafat     = picks.includes(player.id)
                                                const meu        = meusPicks.includes(player.id)
                                                const owner      = agafat ? propietari(player.id) : null
                                                const comptEquip = meusDeEquipReal(player.equipo_real)
                                                const limitEquip = !meu && comptEquip >= maxEquip
                                                const limitPosicio = !meu && meusDePos(player.posicion) >= (LIMIT_POSICIO[player.posicion] ?? 99)
                                                const pot        = esMeuTorn && !agafat && !limitEquip && !limitPosicio
                                                const colors     = POS_COLORS[player.posicion]
                                                return renderCard(player, { agafat, meu, owner, comptEquip, limitEquip, limitPosicio, pot, colors })
                                            })}
                                        </div>
                                    ) : (
                                        /* Vista agrupada per posició */
                                        <div className="space-y-6">
                                            {(posicioFiltro === 'Tots' ? posicions : [posicioFiltro]).map(pos => {
                                                const del = jugadorsFiltrats.filter(p => p.posicion === pos)
                                                if (!del.length) return null
                                                const colors = POS_COLORS[pos]
                                                const comptActualPos = meusDePos(pos)
                                                const maxPosActual   = LIMIT_POSICIO[pos] ?? 99
                                                const posPlena       = comptActualPos >= maxPosActual
                                                return (
                                                    <div key={pos}>
                                                        <div className="flex items-center gap-2 mb-3">
                                                            <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${colors.bg} ${colors.text}`}>
                                                                {pos.toUpperCase()}
                                                            </span>
                                                            <span className="text-gray-500 text-xs">{del.length} disponibles</span>
                                                            {/* Comptador de la posició */}
                                                            <span className={`ml-auto text-xs font-bold px-2 py-0.5 rounded-full ${posPlena ? 'bg-red-900 text-red-300' : 'bg-gray-800 text-gray-300'}`}>
                                                                {posPlena ? ' ' : ''}{comptActualPos}/{maxPosActual} teus
                                                            </span>
                                                        </div>
                                                        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 xl:grid-cols-3 2xl:grid-cols-4 gap-3">
                                                            {del.map(player => {
                                                                const agafat     = picks.includes(player.id)
                                                                const meu        = meusPicks.includes(player.id)
                                                                const owner      = agafat ? propietari(player.id) : null
                                                                const comptEquip = meusDeEquipReal(player.equipo_real)
                                                                const limitEquip  = !meu && comptEquip >= maxEquip
                                                                const limitPosicio = !meu && comptActualPos >= maxPosActual
                                                                const pot        = esMeuTorn && !agafat && !limitEquip && !limitPosicio
                                                                return renderCard(player, { agafat, meu, owner, comptEquip, limitEquip, limitPosicio, pot, colors })
                                                            })}
                                                        </div>
                                                    </div>
                                                )
                                            })}
                                        </div>
                                    )}
                                </div>

                                {/* ── DRETA: Ordre del draft ── */}
                                <div className="w-full xl:w-64 flex-shrink-0">
                                    <div className="bg-gray-900 border border-gray-700 rounded-xl overflow-hidden sticky top-4">
                                        <div className="px-4 py-3 border-b border-gray-700">
                                            <p className="text-white font-semibold text-sm">Ordre del draft</p>
                                            <p className="text-gray-500 text-xs mt-0.5">
                                                {picks.length} picks realitzats · {ordre.length} participants
                                            </p>
                                        </div>
                                        <div className="overflow-y-auto max-h-[600px]">
                                            {generarTorns().map(({ t, uid, nom, esCurrent, esPassat, esMeu }) => (
                                                <div key={t}
                                                     className={`flex items-center gap-2 px-3 py-2 border-b border-gray-800 transition
                                                         ${esCurrent
                                                             ? 'bg-green-900/40 border-l-2 border-l-green-500'
                                                             : esPassat
                                                                 ? 'opacity-40'
                                                                 : ''
                                                         }`}>
                                                    <span className={`text-xs w-7 text-center font-mono flex-shrink-0
                                                        ${esCurrent ? 'text-green-400 font-bold' : 'text-gray-600'}`}>
                                                        {t + 1}
                                                    </span>
                                                    <span className={`text-xs flex-1 truncate font-medium
                                                        ${esCurrent ? 'text-green-300' : esMeu ? 'text-yellow-300' : 'text-gray-300'}`}>
                                                        {nom}
                                                        {esMeu && !esCurrent && <span className="text-gray-600 text-[10px] ml-1">(tu)</span>}
                                                    </span>
                                                    {esCurrent && <span className="text-green-400 text-xs">←</span>}
                                                    {esPassat && (
                                                        <span className="text-gray-600 text-[10px]">
                                                            {picksDetall.find(pk => {
                                                                const r = Math.floor(t / n)
                                                                const ord = r % 2 === 0 ? ordre : [...ordre].reverse()
                                                                return ord[t % n] === pk.user_id
                                                            })
                                                                ? players.find(pl => {
                                                                    const r = Math.floor(t / n)
                                                                    const ord = r % 2 === 0 ? ordre : [...ordre].reverse()
                                                                    const uid2 = ord[t % n]
                                                                    return picksDetall.find(pk => pk.user_id === uid2 && pl.id === pk.player_id)
                                                                })?.nombre?.split(' ').pop() || '✓'
                                                                : ''
                                                            }
                                                        </span>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>

                            </div>
                    )}

                </div>
            </main>

            {/* ── Barra de confirmació (sticky baix) ── */}
            {jugadorPreSel && esMeuTorn && (
                <div className="fixed bottom-0 left-0 right-0 z-40 bg-gray-950/95 border-t border-green-600 backdrop-blur-sm p-4">
                    <div className="max-w-2xl mx-auto flex items-center gap-4">
                        <div className="flex-1 min-w-0">
                            <p className="text-white font-semibold truncate">{jugadorPreSel.nombre}</p>
                            <p className="text-gray-400 text-xs">{jugadorPreSel.equipo_real} · {jugadorPreSel.posicion}</p>
                        </div>
                        <button onClick={() => setJugadorPreSel(null)}
                                className="text-gray-400 hover:text-white text-sm px-3 py-2 transition">
                            Cancel·lar
                        </button>
                        <button
                            onClick={() => setJugadorPreSel(prev => ({ ...prev, confirmPopup: true }))}
                            className="bg-green-500 hover:bg-green-400 text-white font-bold px-6 py-2.5 rounded-xl transition text-sm">
                            ✓ Confirma selecció draft
                        </button>
                    </div>
                </div>
            )}

            {/* ── Modal de confirmació ── */}
            {jugadorPreSel?.confirmPopup && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4">
                    <div className="bg-gray-900 border border-gray-700 rounded-2xl p-6 max-w-sm w-full shadow-2xl">
                        <div className="text-center mb-5">
                            <div className="text-4xl mb-3">⚽</div>
                            <h3 className="text-white font-bold text-lg mb-1">Confirmar selecció</h3>
                            <p className="text-gray-400 text-sm">
                                Segur que vols confirmar a{' '}
                                <span className="text-white font-semibold">{jugadorPreSel.nombre}</span>?
                            </p>
                            <p className="text-gray-500 text-xs mt-1">{jugadorPreSel.equipo_real} · {jugadorPreSel.posicion}</p>
                        </div>
                        <div className="flex gap-3">
                            <button
                                onClick={() => setJugadorPreSel(prev => ({ ...prev, confirmPopup: false }))}
                                disabled={confirmant}
                                className="flex-1 bg-gray-800 hover:bg-gray-700 text-white py-2.5 rounded-xl font-medium transition disabled:opacity-50">
                                Cancel·lar
                            </button>
                            <button
                                onClick={() => pickPlayer(jugadorPreSel.id)}
                                disabled={confirmant}
                                className="flex-1 bg-green-500 hover:bg-green-400 text-white py-2.5 rounded-xl font-bold transition disabled:opacity-50">
                                {confirmant ? 'Confirmant...' : 'Confirmar'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '../../lib/supabase'
import Link from 'next/link'
import Navbar from '../components/Navbar'

const TEMPORADA = '2026-27'

const FORMACIONS = {
    '4-4-2':  { Porter: 1, Defensa: 4, Migcampista: 4, Davanter: 2 },
    '4-3-3':  { Porter: 1, Defensa: 4, Migcampista: 3, Davanter: 3 },
    '4-5-1':  { Porter: 1, Defensa: 4, Migcampista: 5, Davanter: 1 },
    '3-4-3':  { Porter: 1, Defensa: 3, Migcampista: 4, Davanter: 3 },
    '3-5-2':  { Porter: 1, Defensa: 3, Migcampista: 5, Davanter: 2 },
    '5-4-1':  { Porter: 1, Defensa: 5, Migcampista: 4, Davanter: 1 },
    '5-3-2':  { Porter: 1, Defensa: 5, Migcampista: 3, Davanter: 2 },
}

const POS_COLORS = {
    Porter:      { bg: 'bg-yellow-400', text: 'text-yellow-900', border: 'border-yellow-300', light: 'bg-yellow-900/40' },
    Defensa:     { bg: 'bg-blue-500',   text: 'text-blue-900',   border: 'border-blue-400',   light: 'bg-blue-900/40' },
    Migcampista: { bg: 'bg-green-400',  text: 'text-green-900',  border: 'border-green-400',  light: 'bg-green-900/40' },
    Davanter:    { bg: 'bg-red-500',    text: 'text-red-900',    border: 'border-red-400',    light: 'bg-red-900/40' },
}

export default function Equip() {
    const [user, setUser]               = useState(null)
    const [jugadors, setJugadors]       = useState([])
    const [perfil, setPerfil]           = useState(null)
    const [team, setTeam]               = useState(null)
    const [formacio, setFormacio]       = useState('4-4-2')
    const [titulars, setTitulars]       = useState({})
    const [seleccionat, setSeleccionat] = useState(null)
    const [loading, setLoading]         = useState(true)
    const [desant, setDesant]           = useState(false)
    const [maxJugadors, setMaxJugadors] = useState(15)
    const router = useRouter()

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) router.push('/login')
            else { setUser(data.user); fetchTot(data.user.id) }
        })
    }, [])

    async function fetchTot(userId) {
        const { data: perfilData } = await supabase.from('profiles').select('*').eq('id', userId).single()
        setPerfil(perfilData)
        const { data: draftData } = await supabase.from('drafts').select('max_jugadors').single()
        if (draftData) setMaxJugadors(draftData.max_jugadors || 15)
        const { data: picks } = await supabase.from('draft_picks').select('player_id').eq('user_id', userId)
        if (picks?.length) {
            const { data: players } = await supabase.from('players').select('*').in('id', picks.map(p => p.player_id))
            setJugadors(players || [])
        }
        const { data: teamData } = await supabase.from('teams').select('*').eq('user_id', userId).single()
        if (teamData) {
            setTeam(teamData)
            setFormacio(teamData.formacio || '4-4-2')
            setTitulars(teamData.alineacio || {})
        }
        setLoading(false)
    }

    async function desarAuto(nousTitulars, novaFormacio) {
        if (!user) return
        setDesant(true)
        const payload = {
            user_id: user.id,
            temporada: TEMPORADA,
            formacio: novaFormacio ?? formacio,
            alineacio: nousTitulars ?? titulars,
            suplents: []
        }
        if (team) {
            await supabase.from('teams').update(payload).eq('user_id', user.id)
        } else {
            const { data } = await supabase.from('teams').insert(payload).select().single()
            setTeam(data)
        }
        setTimeout(() => setDesant(false), 800)
    }

    function canviarFormacio(novaFormacio) {
        const nova = FORMACIONS[novaFormacio]
        const actual = FORMACIONS[formacio]

        // Mantenim titulars que segueixen tenint slot a la nova formació
        const nousTitulars = {}
        const posicions = ['Porter', 'Defensa', 'Migcampista', 'Davanter']

        posicions.forEach(pos => {
            const slotsNous = nova[pos] || 0
            const slotsActuals = actual[pos] || 0
            // Mantenim fins al mínim de slots entre les dues formacions
            const slotsAMantenir = Math.min(slotsNous, slotsActuals)
            for (let i = 0; i < slotsAMantenir; i++) {
                const key = `${pos}_${i}`
                if (titulars[key]) nousTitulars[key] = titulars[key]
            }
        })

        setFormacio(novaFormacio)
        setTitulars(nousTitulars)
        setSeleccionat(null)
        desarAuto(nousTitulars, novaFormacio)
    }

    function potJugarDe(jugador, posicio) {
        if (!jugador) return false
        if (jugador.posicion === 'Porter') return posicio === 'Porter'
        if (posicio === 'Porter') return jugador.posicion === 'Porter'
        return jugador.posicion === posicio
    }

    function nomCurt(nom) {
        if (!nom) return ''
        const parts = nom.trim().split(' ')
        const cognom = parts[parts.length - 1]
        return cognom.length > 10 ? cognom.slice(0, 10) : cognom
    }

    function handleClickSlot(posicio, index) {
        const key = `${posicio}_${index}`
        const jugadorActualId = titulars[key]

        if (!seleccionat) {
            if (jugadorActualId) setSeleccionat({ tipus: 'titular', key, posicio, id: jugadorActualId })
            else setSeleccionat({ tipus: 'slot-buit', key, posicio, id: null })
            return
        }

        if (seleccionat.key === key) { setSeleccionat(null); return }

        const jugadorMovent = jugadors.find(j => j.id === seleccionat.id)

        if (jugadorMovent && !potJugarDe(jugadorMovent, posicio)) {
            alert(`${jugadorMovent.nombre} és ${jugadorMovent.posicion} i no pot jugar de ${posicio}`)
            setSeleccionat(null)
            return
        }

        const nousTitulars = { ...titulars }

        if (seleccionat.tipus === 'titular') {
            const jugadorDestinacioId = jugadorActualId
            const jugadorDestinacio = jugadors.find(j => j.id === jugadorDestinacioId)
            if (jugadorDestinacioId && !potJugarDe(jugadorDestinacio, seleccionat.posicio)) {
                alert(`${jugadorDestinacio.nombre} no pot jugar de ${seleccionat.posicio}`)
                setSeleccionat(null)
                return
            }
            nousTitulars[key] = seleccionat.id
            if (jugadorDestinacioId) nousTitulars[seleccionat.key] = jugadorDestinacioId
            else delete nousTitulars[seleccionat.key]
        } else if (seleccionat.tipus === 'banqueta' || seleccionat.tipus === 'slot-buit') {
            if (seleccionat.id) {
                if (jugadorActualId) delete nousTitulars[key]
                nousTitulars[key] = seleccionat.id
            }
        }

        setTitulars(nousTitulars)
        setSeleccionat(null)
        desarAuto(nousTitulars)
    }

    function handleClickBanqueta(jugador) {
        if (!seleccionat) {
            setSeleccionat({ tipus: 'banqueta', id: jugador.id })
            return
        }
        if (seleccionat.id === jugador.id) { setSeleccionat(null); return }

        if (seleccionat.tipus === 'titular') {
            // Intercanvi titular ↔ banqueta
            const nousTitulars = { ...titulars }
            nousTitulars[seleccionat.key] = jugador.id
            setTitulars(nousTitulars)
            setSeleccionat(null)
            desarAuto(nousTitulars)
            return
        }

        setSeleccionat({ tipus: 'banqueta', id: jugador.id })
    }

    const formacioActual = FORMACIONS[formacio]
    const titularsIds = Object.values(titulars).filter(Boolean)
    const jugadorsLliures = jugadors.filter(j => !titularsIds.includes(j.id))

    function renderSlot(posicio, index) {
        const key = `${posicio}_${index}`
        const jugadorId = titulars[key]
        const jugador = jugadors.find(j => j.id === jugadorId)
        const colors = POS_COLORS[posicio]
        const esSeleccionat = seleccionat?.key === key || (jugadorId && seleccionat?.id === jugadorId)
        const jugadorMovent = seleccionat ? jugadors.find(j => j.id === seleccionat?.id) : null
        const esCompatible = jugadorMovent ? potJugarDe(jugadorMovent, posicio) : false
        const mostraDestinacio = seleccionat && !esSeleccionat && esCompatible && !jugadorId

        return (
            <div key={key} className="flex flex-col items-center" style={{ width: 64 }}>
                <div
                    onClick={() => handleClickSlot(posicio, index)}
                    className={`
            w-14 h-14 rounded-full border-2 flex items-center justify-center cursor-pointer
            transition-all duration-150 select-none
            ${jugador
                        ? `${colors.bg} ${colors.border}`
                        : mostraDestinacio
                            ? 'border-dashed border-white bg-white/15 animate-pulse'
                            : 'border-dashed border-white/20 bg-black/20'
                    }
            ${esSeleccionat ? 'ring-4 ring-white scale-110 shadow-lg' : 'hover:scale-105'}
          `}
                >
                    {jugador ? (
                        <span className={`text-[10px] font-bold ${colors.text} text-center leading-tight px-0.5`}>
              {nomCurt(jugador.nombre)}
            </span>
                    ) : (
                        <span className="text-white/20 text-xl">+</span>
                    )}
                </div>
                <span className="text-white/70 text-[10px] mt-1 text-center w-16 truncate font-medium">
          {jugador ? nomCurt(jugador.nombre) : <span className="text-white/20 text-[9px]">{posicio.slice(0,3)}</span>}
        </span>
            </div>
        )
    }

    if (loading) return (
        <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">Carregant...</div>
    )

    return (
        <main className="min-h-screen bg-gray-950 text-white p-3 md:p-6">
            <div className="max-w-5xl mx-auto">

                {/* Capçalera */}
                <div className="flex justify-between items-center mb-4">
                    <div>
                        <h1 className="text-xl font-bold text-green-400">️ {perfil?.nom || user?.email}</h1>
                        <p className="text-gray-500 text-xs">
                            {TEMPORADA} · {jugadors.length}/{maxJugadors} jugadors
                            {desant && <span className="ml-2 text-green-400 animate-pulse">· Desant...</span>}
                        </p>
                    </div>
                    <Link href="/classificacio" className="bg-gray-800 hover:bg-gray-700 px-4 py-2 rounded-lg text-sm transition">
                        Classificació
                    </Link>
                </div>

                {/* Selector formació */}
                <div className="flex gap-1.5 flex-wrap mb-4">
                    {Object.keys(FORMACIONS).map(f => (
                        <button key={f} onClick={() => canviarFormacio(f)}
                                className={`px-3 py-1 rounded-lg text-sm font-mono font-bold transition ${formacio === f ? 'bg-green-500 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                            {f}
                        </button>
                    ))}
                </div>

                {/* Layout horitzontal */}
                <div className="flex gap-4 items-start">

                    {/* Camp de futbol */}
                    <div className="relative rounded-xl overflow-hidden flex-shrink-0"
                         style={{
                             width: 320,
                             height: 480,
                             backgroundImage: `
                repeating-linear-gradient(180deg,
                  rgba(255,255,255,0.04) 0px, rgba(255,255,255,0.04) 40px,
                  transparent 40px, transparent 80px
                ),
                linear-gradient(180deg,
                  #1e5c1e 0%, #246b24 14%, #1e5c1e 28%,
                  #246b24 42%, #1e5c1e 56%,
                  #246b24 70%, #1e5c1e 84%, #246b24 100%
                )
              `,
                             border: '3px solid #14401a',
                             boxShadow: 'inset 0 0 40px rgba(0,0,0,0.4), 0 4px 20px rgba(0,0,0,0.5)'
                         }}>

                        <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 320 480" preserveAspectRatio="none">
                            <rect x="8" y="8" width="304" height="464" fill="none" stroke="rgba(255,255,255,0.35)" strokeWidth="1.5"/>
                            <line x1="8" y1="240" x2="312" y2="240" stroke="rgba(255,255,255,0.35)" strokeWidth="1"/>
                            <circle cx="160" cy="240" r="40" fill="none" stroke="rgba(255,255,255,0.35)" strokeWidth="1"/>
                            <circle cx="160" cy="240" r="2" fill="rgba(255,255,255,0.5)"/>
                            <rect x="60" y="8" width="200" height="65" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="100" y="8" width="120" height="28" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="60" y="407" width="200" height="65" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="100" y="444" width="120" height="28" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="120" y="2" width="80" height="10" fill="none" stroke="rgba(255,255,255,0.4)" strokeWidth="1.5"/>
                            <rect x="120" y="468" width="80" height="10" fill="none" stroke="rgba(255,255,255,0.4)" strokeWidth="1.5"/>
                            <circle cx="160" cy="55" r="2.5" fill="rgba(255,255,255,0.4)"/>
                            <circle cx="160" cy="425" r="2.5" fill="rgba(255,255,255,0.4)"/>
                        </svg>

                        <div className="absolute inset-0 flex flex-col justify-between" style={{ padding: '20px 10px' }}>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Davanter }).map((_, i) => renderSlot('Davanter', i))}
                            </div>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Migcampista }).map((_, i) => renderSlot('Migcampista', i))}
                            </div>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Defensa }).map((_, i) => renderSlot('Defensa', i))}
                            </div>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Porter }).map((_, i) => renderSlot('Porter', i))}
                            </div>
                        </div>
                    </div>

                    {/* Panell lateral */}
                    <div className="flex-1 flex flex-col gap-3 min-w-0">

                        {/* Info seleccionat */}
                        {seleccionat && (
                            <div className="bg-green-900/50 border border-green-600 rounded-xl p-3">
                                <p className="text-green-300 text-sm font-semibold">
                                    {seleccionat.id
                                        ? `✓ ${jugadors.find(j => j.id === seleccionat.id)?.nombre} seleccionat`
                                        : 'Slot buit — clica un jugador'}
                                </p>
                                <p className="text-green-500 text-xs mt-0.5">
                                    Clica on el vols posar · slots compatibles parpadegen
                                </p>
                                <button onClick={() => setSeleccionat(null)} className="text-green-600 text-xs mt-1 hover:text-green-400">
                                    Cancel·lar ✕
                                </button>
                            </div>
                        )}

                        {/* Banqueta */}
                        <div className="bg-gray-900 border border-gray-700 rounded-xl p-3 overflow-y-auto" style={{ maxHeight: 420 }}>
                            <p className="text-gray-400 text-xs font-semibold uppercase tracking-wider mb-2">
                                Banqueta ({jugadorsLliures.length})
                            </p>
                            {jugadorsLliures.length === 0 ? (
                                <p className="text-gray-600 text-xs text-center py-6">Tots els jugadors col·locats! </p>
                            ) : (
                                <div className="space-y-1">
                                    {['Porter', 'Defensa', 'Migcampista', 'Davanter'].map(pos => {
                                        const delPos = jugadorsLliures.filter(j => j.posicion === pos)
                                        if (!delPos.length) return null
                                        return (
                                            <div key={pos}>
                                                <p className="text-gray-600 text-[10px] uppercase tracking-wider mt-2 mb-1">{pos}s</p>
                                                {delPos.map(j => {
                                                    const colors = POS_COLORS[j.posicion]
                                                    const esSelec = seleccionat?.id === j.id
                                                    return (
                                                        <div key={j.id} onClick={() => handleClickBanqueta(j)}
                                                             className={`flex items-center gap-2 p-2 rounded-lg cursor-pointer transition-all mb-1
                                ${esSelec ? `${colors.light} border ${colors.border}` : 'hover:bg-gray-800'}`}>
                              <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full flex-shrink-0 ${colors.bg} ${colors.text}`}>
                                {pos.slice(0, 3).toUpperCase()}
                              </span>
                                                            <span className="text-white text-xs font-medium flex-1 truncate">{j.nombre}</span>
                                                            <span className="text-gray-500 text-[10px] truncate hidden md:block">{j.equipo_real}</span>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )
                                    })}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                <p className="text-gray-700 text-xs text-center mt-3">
                    Clica un jugador → clica on el vols posar · Els canvis es desen automàticament
                </p>
            </div>
        </main>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '../../lib/supabase'
import Link from 'next/link'
import Navbar from '../components/Navbar'

const TEMPORADA = '2026-27'

const FORMACIONS = {
    '4-4-2':  { Porter: 1, Defensa: 4, Migcampista: 4, Davanter: 2 },
    '4-3-3':  { Porter: 1, Defensa: 4, Migcampista: 3, Davanter: 3 },
    '4-5-1':  { Porter: 1, Defensa: 4, Migcampista: 5, Davanter: 1 },
    '3-4-3':  { Porter: 1, Defensa: 3, Migcampista: 4, Davanter: 3 },
    '3-5-2':  { Porter: 1, Defensa: 3, Migcampista: 5, Davanter: 2 },
    '5-4-1':  { Porter: 1, Defensa: 5, Migcampista: 4, Davanter: 1 },
    '5-3-2':  { Porter: 1, Defensa: 5, Migcampista: 3, Davanter: 2 },
}

const POS_COLORS = {
    Porter:      { bg: 'bg-yellow-400', text: 'text-yellow-900', border: 'border-yellow-300', light: 'bg-yellow-900/40' },
    Defensa:     { bg: 'bg-blue-500',   text: 'text-blue-900',   border: 'border-blue-400',   light: 'bg-blue-900/40' },
    Migcampista: { bg: 'bg-green-400',  text: 'text-green-900',  border: 'border-green-400',  light: 'bg-green-900/40' },
    Davanter:    { bg: 'bg-red-500',    text: 'text-red-900',    border: 'border-red-400',    light: 'bg-red-900/40' },
}

export default function Equip() {
    const [user, setUser]               = useState(null)
    const [jugadors, setJugadors]       = useState([])
    const [perfil, setPerfil]           = useState(null)
    const [team, setTeam]               = useState(null)
    const [formacio, setFormacio]       = useState('4-4-2')
    const [titulars, setTitulars]       = useState({})
    const [seleccionat, setSeleccionat] = useState(null)
    const [loading, setLoading]         = useState(true)
    const [desant, setDesant]           = useState(false)
    const [maxJugadors, setMaxJugadors] = useState(15)
    const router = useRouter()

    async function fetchTot(userId) {
        const { data: perfilData } = await supabase.from('profiles').select('*').eq('id', userId).single()
        setPerfil(perfilData)
        const { data: draftData } = await supabase.from('drafts').select('max_jugadors').single()
        if (draftData) setMaxJugadors(draftData.max_jugadors || 15)
        const { data: picks } = await supabase.from('draft_picks').select('player_id').eq('user_id', userId)
        if (picks?.length) {
            const { data: players } = await supabase.from('players').select('*').in('id', picks.map(p => p.player_id))
            setJugadors(players || [])
        }
        const { data: teamData } = await supabase.from('teams').select('*').eq('user_id', userId).single()
        if (teamData) {
            setTeam(teamData)
            setFormacio(teamData.formacio || '4-4-2')
            setTitulars(teamData.alineacio || {})
        }
        setLoading(false)
    }

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) router.push('/login')
            else { setUser(data.user); fetchTot(data.user.id) }
        })
    }, [])

    async function desarAuto(nousTitulars, novaFormacio) {
        if (!user) return
        setDesant(true)
        const payload = {
            user_id: user.id,
            temporada: TEMPORADA,
            formacio: novaFormacio ?? formacio,
            alineacio: nousTitulars ?? titulars,
            suplents: []
        }
        if (team) {
            await supabase.from('teams').update(payload).eq('user_id', user.id)
        } else {
            const { data } = await supabase.from('teams').insert(payload).select().single()
            setTeam(data)
        }
        setTimeout(() => setDesant(false), 800)
    }

    function canviarFormacio(novaFormacio) {
        const nova = FORMACIONS[novaFormacio]
        const actual = FORMACIONS[formacio]

        // Mantenim titulars que segueixen tenint slot a la nova formació
        const nousTitulars = {}
        const posicions = ['Porter', 'Defensa', 'Migcampista', 'Davanter']

        posicions.forEach(pos => {
            const slotsNous = nova[pos] || 0
            const slotsActuals = actual[pos] || 0
            // Mantenim fins al mínim de slots entre les dues formacions
            const slotsAMantenir = Math.min(slotsNous, slotsActuals)
            for (let i = 0; i < slotsAMantenir; i++) {
                const key = `${pos}_${i}`
                if (titulars[key]) nousTitulars[key] = titulars[key]
            }
        })

        setFormacio(novaFormacio)
        setTitulars(nousTitulars)
        setSeleccionat(null)
        desarAuto(nousTitulars, novaFormacio)
    }

    function potJugarDe(jugador, posicio) {
        if (!jugador) return false
        if (jugador.posicion === 'Porter') return posicio === 'Porter'
        if (posicio === 'Porter') return jugador.posicion === 'Porter'
        return jugador.posicion === posicio
    }

    function nomCurt(nom) {
        if (!nom) return ''
        const parts = nom.trim().split(' ')
        const cognom = parts[parts.length - 1]
        return cognom.length > 10 ? cognom.slice(0, 10) : cognom
    }

    function handleClickSlot(posicio, index) {
        const key = `${posicio}_${index}`
        const jugadorActualId = titulars[key]

        if (!seleccionat) {
            if (jugadorActualId) setSeleccionat({ tipus: 'titular', key, posicio, id: jugadorActualId })
            else setSeleccionat({ tipus: 'slot-buit', key, posicio, id: null })
            return
        }

        // Deseleccionar si cliquem el mateix
        if (seleccionat.key === key) { setSeleccionat(null); return }

        const jugadorMovent = jugadors.find(j => j.id === seleccionat.id)
        const jugadorActual = jugadors.find(j => j.id === jugadorActualId)

        // Validacio: el jugador que movem pot anar a aquesta posicio?
        if (jugadorMovent && !potJugarDe(jugadorMovent, posicio)) {
            alert(`${jugadorMovent.nombre} és ${jugadorMovent.posicion} i no pot jugar de ${posicio}`)
            setSeleccionat(null)
            return
        }

        // Si hi ha un jugador al desti, validar que pot anar a l'origen
        if (jugadorActual && seleccionat.tipus === 'titular') {
            if (!potJugarDe(jugadorActual, seleccionat.posicio)) {
                alert(`${jugadorActual.nombre} és ${jugadorActual.posicion} i no pot jugar de ${seleccionat.posicio}`)
                setSeleccionat(null)
                return
            }
        }

        const nousTitulars = { ...titulars }

        if (seleccionat.tipus === 'titular') {
            // Intercanvi entre dos slots
            nousTitulars[key] = seleccionat.id
            if (jugadorActualId) nousTitulars[seleccionat.key] = jugadorActualId
            else delete nousTitulars[seleccionat.key]

        } else if (seleccionat.tipus === 'banqueta') {
            // De banqueta a titular - el titular anterior torna a banqueta automaticament
            nousTitulars[key] = seleccionat.id
            if (!jugadorActualId) {
                // slot buit, simplement posem
            }
            // Si hi havia titular, ja no es a titulars -> va a banqueta automaticament
            if (jugadorActualId) delete nousTitulars[key]
            nousTitulars[key] = seleccionat.id
        }

        setTitulars(nousTitulars)
        setSeleccionat(null)
        desarAuto(nousTitulars)
    }

    function handleClickBanqueta(jugador) {
        if (!seleccionat) {
            setSeleccionat({ tipus: 'banqueta', id: jugador.id })
            return
        }

        // Deseleccionar si cliquem el mateix
        if (seleccionat.id === jugador.id) { setSeleccionat(null); return }

        if (seleccionat.tipus === 'titular') {
            // Titular -> banqueta: simplement treiem el titular del camp
            const nousTitulars = { ...titulars }
            delete nousTitulars[seleccionat.key]
            setTitulars(nousTitulars)
            setSeleccionat(null)
            desarAuto(nousTitulars)
            return
        }

        if (seleccionat.tipus === 'banqueta') {
            // Canvi de seleccio dins banqueta
            setSeleccionat({ tipus: 'banqueta', id: jugador.id })
            return
        }

        setSeleccionat(null)
    }

    const formacioActual = FORMACIONS[formacio]
    const titularsIds = Object.values(titulars).filter(Boolean)
    const jugadorsLliures = jugadors.filter(j => !titularsIds.includes(j.id))

    function renderSlot(posicio, index) {
        const key = `${posicio}_${index}`
        const jugadorId = titulars[key]
        const jugador = jugadors.find(j => j.id === jugadorId)
        const colors = POS_COLORS[posicio]
        const esSeleccionat = seleccionat?.key === key || (jugadorId && seleccionat?.id === jugadorId)
        const jugadorMovent = seleccionat ? jugadors.find(j => j.id === seleccionat?.id) : null
        const esCompatible = jugadorMovent ? potJugarDe(jugadorMovent, posicio) : false
        const mostraDestinacio = seleccionat && !esSeleccionat && esCompatible && !jugadorId

        return (
            <div key={key} className="flex flex-col items-center" style={{ width: 64 }}>
                <div
                    onClick={() => handleClickSlot(posicio, index)}
                    className={`
            w-14 h-14 rounded-full border-2 flex items-center justify-center cursor-pointer
            transition-all duration-150 select-none
            ${jugador
                        ? `${colors.bg} ${colors.border}`
                        : mostraDestinacio
                            ? 'border-dashed border-white bg-white/15 animate-pulse'
                            : 'border-dashed border-white/20 bg-black/20'
                    }
            ${esSeleccionat ? 'ring-4 ring-white scale-110 shadow-lg' : 'hover:scale-105'}
          `}
                >
                    {jugador ? (
                        jugador.foto
                            ? <img src={jugador.foto} alt={jugador.nombre}
                                   className="w-full h-full rounded-full object-cover"
                                   onError={e => { e.target.style.display='none'; e.target.nextSibling.style.display='flex' }} />
                            : <span className={`text-[10px] font-bold ${colors.text} text-center leading-tight px-0.5`}>{nomCurt(jugador.nombre)}</span>
                    ) : (
                        <span className="text-white/20 text-xl">+</span>
                    )}
                </div>
                <span className="text-white/70 text-[10px] mt-1 text-center w-16 truncate font-medium">
          {jugador ? nomCurt(jugador.nombre) : <span className="text-white/20 text-[9px]">{posicio.slice(0,3)}</span>}
        </span>
            </div>
        )
    }

    if (loading) return (
        <>
            <Navbar />
            <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">Carregant...</div>
        </>
    )

    return (
        <>
            <Navbar />
            <main className="min-h-screen bg-gray-950 text-white p-3 md:p-6">
            <div className="max-w-5xl mx-auto">

                {/* Capçalera */}
                <div className="flex justify-between items-center mb-4">
                    <div>
                        <h1 className="text-xl font-bold text-green-400">️ {perfil?.nom || user?.email}</h1>
                        <p className="text-gray-500 text-xs">
                            {TEMPORADA} · {jugadors.length}/{maxJugadors} jugadors
                            {desant && <span className="ml-2 text-green-400 animate-pulse">· Desant...</span>}
                        </p>
                    </div>
                    <Link href="/classificacio" className="bg-gray-800 hover:bg-gray-700 px-4 py-2 rounded-lg text-sm transition">
                        Classificació
                    </Link>
                </div>

                {/* Selector formació */}
                <div className="flex gap-1.5 flex-wrap mb-4">
                    {Object.keys(FORMACIONS).map(f => (
                        <button key={f} onClick={() => canviarFormacio(f)}
                                className={`px-3 py-1 rounded-lg text-sm font-mono font-bold transition ${formacio === f ? 'bg-green-500 text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}>
                            {f}
                        </button>
                    ))}
                </div>

                {/* Layout horitzontal */}
                <div className="flex gap-4 items-start">

                    {/* Camp de futbol */}
                    <div className="relative rounded-xl overflow-hidden flex-shrink-0"
                         style={{
                             width: 320,
                             height: 480,
                             backgroundImage: `
                repeating-linear-gradient(180deg,
                  rgba(255,255,255,0.04) 0px, rgba(255,255,255,0.04) 40px,
                  transparent 40px, transparent 80px
                ),
                linear-gradient(180deg,
                  #1e5c1e 0%, #246b24 14%, #1e5c1e 28%,
                  #246b24 42%, #1e5c1e 56%,
                  #246b24 70%, #1e5c1e 84%, #246b24 100%
                )
              `,
                             border: '3px solid #14401a',
                             boxShadow: 'inset 0 0 40px rgba(0,0,0,0.4), 0 4px 20px rgba(0,0,0,0.5)'
                         }}>

                        <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 320 480" preserveAspectRatio="none">
                            <rect x="8" y="8" width="304" height="464" fill="none" stroke="rgba(255,255,255,0.35)" strokeWidth="1.5"/>
                            <line x1="8" y1="240" x2="312" y2="240" stroke="rgba(255,255,255,0.35)" strokeWidth="1"/>
                            <circle cx="160" cy="240" r="40" fill="none" stroke="rgba(255,255,255,0.35)" strokeWidth="1"/>
                            <circle cx="160" cy="240" r="2" fill="rgba(255,255,255,0.5)"/>
                            <rect x="60" y="8" width="200" height="65" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="100" y="8" width="120" height="28" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="60" y="407" width="200" height="65" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="100" y="444" width="120" height="28" fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="1"/>
                            <rect x="120" y="2" width="80" height="10" fill="none" stroke="rgba(255,255,255,0.4)" strokeWidth="1.5"/>
                            <rect x="120" y="468" width="80" height="10" fill="none" stroke="rgba(255,255,255,0.4)" strokeWidth="1.5"/>
                            <circle cx="160" cy="55" r="2.5" fill="rgba(255,255,255,0.4)"/>
                            <circle cx="160" cy="425" r="2.5" fill="rgba(255,255,255,0.4)"/>
                        </svg>

                        <div className="absolute inset-0 flex flex-col justify-between" style={{ padding: '20px 10px' }}>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Davanter }).map((_, i) => renderSlot('Davanter', i))}
                            </div>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Migcampista }).map((_, i) => renderSlot('Migcampista', i))}
                            </div>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Defensa }).map((_, i) => renderSlot('Defensa', i))}
                            </div>
                            <div className="flex justify-around items-center">
                                {Array.from({ length: formacioActual.Porter }).map((_, i) => renderSlot('Porter', i))}
                            </div>
                        </div>
                    </div>

                    {/* Panell lateral */}
                    <div className="flex-1 flex flex-col gap-3 min-w-0">

                        {/* Info seleccionat */}
                        {seleccionat && (
                            <div className="bg-green-900/50 border border-green-600 rounded-xl p-3">
                                <p className="text-green-300 text-sm font-semibold">
                                    {seleccionat.id
                                        ? `✓ ${jugadors.find(j => j.id === seleccionat.id)?.nombre} seleccionat`
                                        : 'Slot buit — clica un jugador'}
                                </p>
                                <p className="text-green-500 text-xs mt-0.5">
                                    Clica on el vols posar · slots compatibles parpadegen
                                </p>
                                <button onClick={() => setSeleccionat(null)} className="text-green-600 text-xs mt-1 hover:text-green-400">
                                    Cancel·lar ✕
                                </button>
                            </div>
                        )}

                        {/* Banqueta */}
                        <div className="bg-gray-900 border border-gray-700 rounded-xl p-3 overflow-y-auto" style={{ maxHeight: 420 }}>
                            <p className="text-gray-400 text-xs font-semibold uppercase tracking-wider mb-2">
                                Banqueta ({jugadorsLliures.length})
                            </p>
                            {jugadorsLliures.length === 0 ? (
                                <p className="text-gray-600 text-xs text-center py-6">Tots els jugadors col·locats! </p>
                            ) : (
                                <div className="space-y-1">
                                    {['Porter', 'Defensa', 'Migcampista', 'Davanter'].map(pos => {
                                        const delPos = jugadorsLliures.filter(j => j.posicion === pos)
                                        if (!delPos.length) return null
                                        return (
                                            <div key={pos}>
                                                <p className="text-gray-600 text-[10px] uppercase tracking-wider mt-2 mb-1">{pos}s</p>
                                                {delPos.map(j => {
                                                    const colors = POS_COLORS[j.posicion]
                                                    const esSelec = seleccionat?.id === j.id
                                                    return (
                                                        <div key={j.id} onClick={() => handleClickBanqueta(j)}
                                                             className={`flex items-center gap-2 p-2 rounded-lg cursor-pointer transition-all mb-1
                                ${esSelec ? `${colors.light} border ${colors.border}` : 'hover:bg-gray-800'}`}>
                              <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full flex-shrink-0 ${colors.bg} ${colors.text}`}>
                                {pos.slice(0, 3).toUpperCase()}
                              </span>
                                                            {j.foto
                                                                ? <img src={j.foto} alt={j.nombre}
                                                                       className="w-7 h-7 rounded-full object-cover flex-shrink-0 bg-gray-700"
                                                                       onError={e => { e.target.style.display='none' }} />
                                                                : null
                                                            }
                                                            <span className="text-white text-xs font-medium flex-1 truncate">{j.nombre}</span>
                                                            <div className="flex items-center gap-1 hidden md:flex">
                                                                {j.escudo_equip && (
                                                                    <img src={j.escudo_equip} alt="" className="w-4 h-4 object-contain"
                                                                         onError={e => { e.target.style.display='none' }} />
                                                                )}
                                                                <span className="text-gray-500 text-[10px] truncate">{j.equipo_real}</span>
                                                            </div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )
                                    })}
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                <p className="text-gray-700 text-xs text-center mt-3">
                    Clica un jugador → clica on el vols posar · Els canvis es desen automàticament
                </p>
            </div>
            </main>
        </>
    )
}

'use client'
import { useState } from 'react'
import { supabase } from '../../lib/supabase'

export default function Login() {
    const [email, setEmail] = useState('')
    const [password, setPassword] = useState('')
    const [missatge, setMissatge] = useState('')
    const [loading, setLoading] = useState(false)
    const [esRegistre, setEsRegistre] = useState(false)

    async function handleEmail() {
        setLoading(true)
        const fn = esRegistre
            ? supabase.auth.signUp({ email, password })
            : supabase.auth.signInWithPassword({ email, password })
        const { error } = await fn
        if (error) setMissatge(error.message)
        else setMissatge(esRegistre ? 'Comprova el teu email per confirmar!' : 'Entrant...')
        setLoading(false)
    }

    async function handleGoogle() {
        await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: { redirectTo: window.location.origin + '/draft' }
        })
    }

    return (
        <main className="min-h-screen bg-gray-950 text-white flex items-center justify-center">
            <div className="bg-gray-900 p-8 rounded-xl w-full max-w-md border border-gray-800">
                <h1 className="text-3xl font-bold text-green-400 mb-2 text-center">⚽ Fantasy Andratx</h1>
                <p className="text-gray-400 text-center mb-8">La lliga dels amics</p>

                <button
                    onClick={handleGoogle}
                    className="w-full bg-white text-gray-900 font-semibold py-3 rounded-lg mb-6 hover:bg-gray-100 transition flex items-center justify-center gap-2"
                >
                    <span></span> Entrar amb Google
                </button>

                <div className="flex items-center gap-3 mb-6">
                    <div className="flex-1 h-px bg-gray-700"/>
                    <span className="text-gray-500 text-sm">o amb email</span>
                    <div className="flex-1 h-px bg-gray-700"/>
                </div>

                <input
                    type="email"
                    placeholder="Email"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 mb-3 text-white placeholder-gray-500 focus:outline-none focus:border-green-500"
                />
                <input
                    type="password"
                    placeholder="Contrasenya"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 mb-4 text-white placeholder-gray-500 focus:outline-none focus:border-green-500"
                />

                {missatge && <p className="text-yellow-400 text-sm mb-4 text-center">{missatge}</p>}

                <button
                    onClick={handleEmail}
                    disabled={loading}
                    className="w-full bg-green-500 hover:bg-green-600 text-white font-semibold py-3 rounded-lg transition mb-3"
                >
                    {loading ? 'Carregant...' : esRegistre ? 'Crear compte' : 'Entrar'}
                </button>

                <button
                    onClick={() => setEsRegistre(!esRegistre)}
                    className="w-full text-gray-400 hover:text-white text-sm transition"
                >
                    {esRegistre ? 'Ja tinc compte → Entrar' : 'Nou usuari → Crear compte'}
                </button>
            </div>
        </main>
    )
}

'use client'
import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '../../lib/supabase'

export default function Login() {
    const [email, setEmail] = useState('')
    const [password, setPassword] = useState('')
    const [missatge, setMissatge] = useState('')
    const [loading, setLoading] = useState(false)
    const [esRegistre, setEsRegistre] = useState(false)
    const router = useRouter()

    // Si ja està autenticat, redirigir a la pàgina principal
    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (data.user) router.push('/')
        })
    }, [])

    async function handleEmail() {
        setLoading(true)

        // Accés directe a admin
        if (email === 'admin' && password === 'fantasy-andratx') {
            sessionStorage.setItem('admin_auth', 'ok')
            router.push('/admin')
            setLoading(false)
            return
        }

        if (esRegistre) {
            const { error } = await supabase.auth.signUp({ email, password })
            if (error) setMissatge(error.message)
            else setMissatge('Comprova el teu email per confirmar!')
        } else {
            const { error } = await supabase.auth.signInWithPassword({ email, password })
            if (error) setMissatge('Email o contrasenya incorrectes')
            else router.push('/')
        }
        setLoading(false)
    }

    async function handleGoogle() {
        await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: { redirectTo: window.location.origin + '/' }
        })
    }

    return (
        <main className="min-h-screen bg-gray-950 text-white flex items-center justify-center">
            <div className="bg-gray-900 p-8 rounded-xl w-full max-w-md border border-gray-800">
                <h1 className="text-3xl font-bold text-green-400 mb-2 text-center">⚽ Fantasy Andratx</h1>
                <p className="text-gray-400 text-center mb-8">La lliga dels amics</p>

                <button
                    onClick={handleGoogle}
                    className="w-full bg-white text-gray-900 font-semibold py-3 rounded-lg mb-6 hover:bg-gray-100 transition flex items-center justify-center gap-2"
                >
                    <span></span> Entrar amb Google
                </button>

                <div className="flex items-center gap-3 mb-6">
                    <div className="flex-1 h-px bg-gray-700"/>
                    <span className="text-gray-500 text-sm">o amb email</span>
                    <div className="flex-1 h-px bg-gray-700"/>
                </div>

                <input
                    type="email"
                    placeholder="Email"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 mb-3 text-white placeholder-gray-500 focus:outline-none focus:border-green-500"
                />
                <input
                    type="password"
                    placeholder="Contrasenya"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-4 py-3 mb-4 text-white placeholder-gray-500 focus:outline-none focus:border-green-500"
                />

                {missatge && <p className="text-yellow-400 text-sm mb-4 text-center">{missatge}</p>}

                <button
                    onClick={handleEmail}
                    disabled={loading}
                    className="w-full bg-green-500 hover:bg-green-600 text-white font-semibold py-3 rounded-lg transition mb-3"
                >
                    {loading ? 'Carregant...' : esRegistre ? 'Crear compte' : 'Entrar'}
                </button>

                <button
                    onClick={() => setEsRegistre(!esRegistre)}
                    className="w-full text-gray-400 hover:text-white text-sm transition"
                >
                    {esRegistre ? 'Ja tinc compte → Entrar' : 'Nou usuari → Crear compte'}
                </button>
            </div>
        </main>
    )
}

'use client'
import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { supabase } from '../lib/supabase'
import Navbar from './components/Navbar'

export default function Home() {
    const [user, setUser] = useState(null)
    const [loading, setLoading] = useState(true)
    const router = useRouter()

    useEffect(() => {
        supabase.auth.getUser().then(({ data }) => {
            if (!data.user) {
                router.push('/login')
            } else {
                setUser(data.user)
                setLoading(false)
            }
        })
    }, [])

    if (loading) return (
        <div className="min-h-screen bg-gray-950 text-white flex items-center justify-center">
            <div className="text-green-400 text-2xl font-bold animate-pulse">⚽ Fantasy Andratx</div>
        </div>
    )

    const seccions = [
        { href: '/classificacio', icon: '', label: 'Classificació',   desc: 'Consulta les classificacions per jornada i general',   color: 'from-yellow-600 to-yellow-800', border: 'border-yellow-600' },
        { href: '/draft',         icon: '⚽', label: 'Draft',           desc: 'Sala de draft — tria els teus jugadors',               color: 'from-green-600 to-green-800',  border: 'border-green-600' },
        { href: '/equip',         icon: '', label: 'El meu equip',    desc: 'Gestiona la teva plantilla i formació',                color: 'from-blue-600 to-blue-800',    border: 'border-blue-600' },
        { href: '/canvis',        icon: '', label: 'Canvis',          desc: 'Ronda de canvis de jugadors',                          color: 'from-purple-600 to-purple-800', border: 'border-purple-600' },
        { href: '/canvi-bomba',   icon: '', label: 'Canvi BOMBA',     desc: 'Canvi especial — una vegada per volta',                color: 'from-red-600 to-red-800',      border: 'border-red-600' },
    ]

    return (
        <>
            <Navbar />
            <main className="min-h-screen bg-gray-950 text-white p-6">
                <div className="max-w-4xl mx-auto">
                    {/* Capçalera */}
                    <div className="text-center mb-10 pt-6">
                        <h1 className="text-5xl font-bold text-green-400 mb-3">⚽ Fantasy Andratx</h1>
                        <p className="text-gray-400 text-lg">La lliga dels amics</p>
                    </div>

                    {/* Grid de seccions */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {seccions.map(s => (
                            <Link key={s.href} href={s.href}
                                  className={`bg-gradient-to-br ${s.color} border ${s.border} rounded-2xl p-6 hover:scale-[1.03] transition-all duration-150 shadow-lg`}>
                                <div className="text-4xl mb-3">{s.icon}</div>
                                <h2 className="text-white font-bold text-xl mb-1">{s.label}</h2>
                                <p className="text-white/70 text-sm">{s.desc}</p>
                            </Link>
                        ))}
                    </div>
                </div>
            </main>
        </>
    )
}

